/**
 * Script untuk hapus file orphan di Supabase Storage
 * (file yang tidak ada referensinya di database)
 * 
 * Usage:
 * npx tsx scripts/cleanup-orphaned-files.ts
 */

import "dotenv/config";
import { PrismaClient } from "@prisma/client";
import { Pool } from "pg";
import { PrismaPg } from "@prisma/adapter-pg";
import { supabaseAdmin, STORAGE_BUCKET, extractPathFromUrl } from "../src/lib/supabase";

const connectionString = process.env.DATABASE_URL;
if (!connectionString) {
  console.error("❌ DATABASE_URL tidak ditemukan di .env");
  process.exit(1);
}

const pool = new Pool({ connectionString });
const adapter = new PrismaPg(pool);
const prisma = new PrismaClient({ adapter });

async function cleanupOrphanedFiles() {
  console.log("🔍 Mencari file orphan di Supabase Storage...\n");

  try {
    // 1. Get all files from Supabase Storage
    console.log("📦 Mengambil daftar file dari Supabase Storage...");
    const { data: files, error } = await supabaseAdmin.storage
      .from(STORAGE_BUCKET)
      .list();

    if (error) {
      console.error("❌ Error mengambil file dari Supabase:", error);
      return;
    }

    if (!files || files.length === 0) {
      console.log("✅ Tidak ada file di Supabase Storage");
      return;
    }

    console.log(`   ✅ Ditemukan ${files.length} file di Supabase Storage\n`);

    // 2. Get all URLs from database
    console.log("🗄️  Mengambil daftar URL dari database...");
    
    const [anggota, berita, artikel, kegiatan, program, galeri] = await Promise.all([
      prisma.anggota.findMany({ select: { foto: true } }),
      prisma.berita.findMany({ select: { thumbnail: true } }),
      prisma.artikel.findMany({ select: { thumbnail: true } }),
      prisma.kegiatan.findMany({ select: { thumbnail: true } }),
      prisma.program.findMany({ select: { thumbnail: true } }),
      prisma.galeriItem.findMany({ select: { url: true } }),
    ]);

    // Collect all URLs
    const usedUrls = new Set<string>();
    
    anggota.forEach(a => a.foto && usedUrls.add(a.foto));
    berita.forEach(b => b.thumbnail && usedUrls.add(b.thumbnail));
    artikel.forEach(a => a.thumbnail && usedUrls.add(a.thumbnail));
    kegiatan.forEach(k => k.thumbnail && usedUrls.add(k.thumbnail));
    program.forEach(p => p.thumbnail && usedUrls.add(p.thumbnail));
    galeri.forEach(g => usedUrls.add(g.url));

    console.log(`   ✅ Ditemukan ${usedUrls.size} URL yang digunakan di database\n`);

    // 3. Extract paths from URLs
    const usedPaths = new Set<string>();
    usedUrls.forEach(url => {
      const path = extractPathFromUrl(url);
      if (path) usedPaths.add(path);
    });

    // 4. Find orphaned files
    const orphanedFiles: string[] = [];
    
    files.forEach(file => {
      if (!file.name) return;
      
      // Check if file is used in database
      if (!usedPaths.has(file.name)) {
        orphanedFiles.push(file.name);
      }
    });

    if (orphanedFiles.length === 0) {
      console.log("✅ Tidak ada file orphan ditemukan!");
      console.log("   Semua file di Supabase Storage masih digunakan di database");
      return;
    }

    console.log(`⚠️  Ditemukan ${orphanedFiles.length} file orphan:\n`);
    orphanedFiles.forEach((file, index) => {
      console.log(`   ${index + 1}. ${file}`);
    });

    // 5. Konfirmasi
    console.log("\n⚠️  PERINGATAN: File-file ini akan dihapus dari Supabase Storage!");
    console.log("⏳ Menunggu 5 detik... (Ctrl+C untuk cancel)");
    await new Promise((resolve) => setTimeout(resolve, 5000));

    // 6. Delete orphaned files
    console.log("\n🗑️  Menghapus file orphan...\n");
    
    const { error: deleteError } = await supabaseAdmin.storage
      .from(STORAGE_BUCKET)
      .remove(orphanedFiles);

    if (deleteError) {
      console.error("❌ Error menghapus file:", deleteError);
      return;
    }

    console.log(`✅ CLEANUP SELESAI!`);
    console.log(`   ${orphanedFiles.length} file orphan berhasil dihapus dari Supabase Storage`);

    // 7. Show storage stats
    const remainingFiles = files.length - orphanedFiles.length;
    console.log(`\n📊 Storage Statistics:`);
    console.log(`   Total file sebelumnya: ${files.length}`);
    console.log(`   File dihapus: ${orphanedFiles.length}`);
    console.log(`   File tersisa: ${remainingFiles}`);

  } catch (error: any) {
    console.error("\n❌ ERROR:", error.message);
    console.error(error);
  } finally {
    await prisma.$disconnect();
    await pool.end();
  }
}

// Main
console.log("🧹 CLEANUP ORPHANED FILES\n");
console.log("Script ini akan mencari dan menghapus file di Supabase Storage");
console.log("yang tidak ada referensinya di database.\n");

cleanupOrphanedFiles();

/**
 * Script untuk hapus user dan semua data terkait termasuk file di Supabase Storage
 * 
 * Usage:
 * npx tsx scripts/cleanup-user.ts "nama@email.com"
 * atau
 * npx tsx scripts/cleanup-user.ts "Nama Lengkap"
 */

import "dotenv/config"; // Load .env file
import { PrismaClient } from "@prisma/client";
import { Pool } from "pg";
import { PrismaPg } from "@prisma/adapter-pg";
import { deleteFileFromStorage } from "../src/lib/supabase";

const connectionString = process.env.DATABASE_URL;
if (!connectionString) {
  console.error("❌ DATABASE_URL tidak ditemukan di .env");
  process.exit(1);
}

const pool = new Pool({ connectionString });
const adapter = new PrismaPg(pool);
const prisma = new PrismaClient({ adapter });

async function cleanupUser(identifier: string) {
  console.log("🔍 Mencari user:", identifier);

  // Cari user berdasarkan email atau nama
  const user = await prisma.user.findFirst({
    where: {
      OR: [
        { email: { contains: identifier, mode: "insensitive" } },
        { name: { contains: identifier, mode: "insensitive" } },
      ],
    },
    include: {
      anggota: true,
      admin: true,
    },
  });

  if (!user) {
    console.log("❌ User tidak ditemukan");
    return;
  }

  console.log("\n📋 User ditemukan:");
  console.log("   ID:", user.id);
  console.log("   Nama:", user.name);
  console.log("   Email:", user.email);
  console.log("   Role:", user.role);

  // Konfirmasi
  console.log("\n⚠️  PERINGATAN: Ini akan menghapus:");
  console.log("   - Data user dari database");
  console.log("   - Data anggota (jika ada)");
  console.log("   - Data admin (jika ada)");
  console.log("   - Foto profil dari Supabase Storage");
  console.log("   - Semua data terkait (votes, aspirasi, notifikasi, dll)");

  // Tunggu 3 detik untuk cancel
  console.log("\n⏳ Menunggu 3 detik... (Ctrl+C untuk cancel)");
  await new Promise((resolve) => setTimeout(resolve, 3000));

  console.log("\n🗑️  Memulai proses cleanup...\n");

  try {
    // 1. Hapus foto profil dari Supabase jika ada
    if (user.anggota?.foto) {
      console.log("📸 Menghapus foto profil dari Supabase...");
      const deleted = await deleteFileFromStorage(user.anggota.foto);
      if (deleted) {
        console.log("   ✅ Foto profil berhasil dihapus");
      } else {
        console.log("   ⚠️  Foto profil tidak ditemukan atau sudah dihapus");
      }
    }

    // 2. Hapus data anggota (cascade akan hapus relasi)
    if (user.anggota) {
      console.log("👤 Menghapus data anggota...");
      await prisma.anggota.delete({
        where: { id: user.anggota.id },
      });
      console.log("   ✅ Data anggota berhasil dihapus");
    }

    // 3. Hapus data admin (jika ada)
    if (user.admin) {
      console.log("👔 Menghapus data admin...");
      await prisma.admin.delete({
        where: { id: user.admin.id },
      });
      console.log("   ✅ Data admin berhasil dihapus");
    }

    // 4. Hapus user (cascade akan hapus votes, aspirasi, notifikasi, dll)
    console.log("🗑️  Menghapus user...");
    await prisma.user.delete({
      where: { id: user.id },
    });
    console.log("   ✅ User berhasil dihapus");

    console.log("\n✅ CLEANUP SELESAI!");
    console.log("   User dan semua data terkait berhasil dihapus dari database dan Supabase Storage");
  } catch (error: any) {
    console.error("\n❌ ERROR:", error.message);
    console.error(error);
  } finally {
    await prisma.$disconnect();
    await pool.end();
  }
}

// Main
const identifier = process.argv[2];

if (!identifier) {
  console.log("❌ Usage: npx tsx scripts/cleanup-user.ts <email atau nama>");
  console.log("\nContoh:");
  console.log('  npx tsx scripts/cleanup-user.ts "budi@example.com"');
  console.log('  npx tsx scripts/cleanup-user.ts "Budi Santoso"');
  process.exit(1);
}

cleanupUser(identifier);

"use server";

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import bcrypt from "bcryptjs";
import { deleteFileFromStorage } from "@/lib/supabase";
import { auditUpdate, auditDelete, auditCreate } from "@/lib/audit";
import { auth } from "@/auth";

export async function updateAnggota(id: string, formData: FormData) {
  const session = await auth();
  const namaLengkap = formData.get("namaLengkap") as string;
  const nik = formData.get("nik") as string;
  const tempatLahir = formData.get("tempatLahir") as string;
  const tanggalLahir = formData.get("tanggalLahir") as string;
  const jenisKelamin = formData.get("jenisKelamin") as "LAKI_LAKI" | "PEREMPUAN";
  const alamat = formData.get("alamat") as string;
  const noHp = formData.get("noHp") as string;
  const email = formData.get("email") as string;
  const pekerjaan = formData.get("pekerjaan") as string;
  const pendidikan = formData.get("pendidikan") as string;
  const status = formData.get("status") as "AKTIF" | "NON_AKTIF" | "ALUMNI";
  const foto = formData.get("foto") as string;

  if (!namaLengkap || !nik || !jenisKelamin) {
    throw new Error("Data tidak lengkap");
  }

  // Ambil userId dulu sebelum update
  const existing = await prisma.anggota.findUnique({
    where: { id },
    select: { userId: true },
  });

  try {
    await prisma.anggota.update({
      where: { id },
      data: {
        namaLengkap,
        nik,
        tempatLahir: tempatLahir || null,
        tanggalLahir: tanggalLahir ? new Date(tanggalLahir) : null,
        jenisKelamin,
        alamat: alamat || null,
        noHp: noHp || null,
        email: email || null,
        pekerjaan: pekerjaan || null,
        pendidikan: pendidikan || null,
        foto: foto || null,
        status,
      },
    });

    // Sync nama ke User terkait jika ada
    if (existing?.userId) {
      await prisma.user.update({
        where: { id: existing.userId },
        data: { name: namaLengkap },
      }).catch(() => {});
    }

    // Audit log
    await auditUpdate(
      "anggota",
      id,
      namaLengkap,
      session?.user?.id,
      session?.user?.name || undefined,
      `Updated anggota: ${namaLengkap} (${nik})`
    );
  } catch (error: any) {
    if (error.code === "P2002") {
      throw new Error("NIK sudah terdaftar oleh anggota lain");
    }
    throw new Error("Gagal mengupdate data anggota");
  }

  revalidatePath("/dashboard/anggota");
  redirect("/dashboard/anggota");
}

export async function deleteAnggota(id: string) {
  const session = await auth();
  
  // Cari data anggota sebelum hapus untuk ambil foto dan userId
  const anggota = await prisma.anggota.findUnique({
    where: { id },
    select: { userId: true, foto: true, namaLengkap: true, nik: true },
  });

  if (!anggota) {
    throw new Error("Anggota tidak ditemukan");
  }

  try {
    // Hapus foto dari Supabase Storage jika ada
    if (anggota.foto) {
      await deleteFileFromStorage(anggota.foto);
    }

    // Hapus data anggota dari database
    await prisma.anggota.delete({ where: { id } });

    // Hapus User terkait jika ada
    if (anggota.userId) {
      await prisma.user
        .delete({ where: { id: anggota.userId } })
        .catch(() => {});
    }

    // Audit log
    await auditDelete(
      "anggota",
      id,
      anggota.namaLengkap,
      session?.user?.id,
      session?.user?.name || undefined,
      `Deleted anggota: ${anggota.namaLengkap} (${anggota.nik})`
    );
  } catch (error) {
    console.error("[DELETE_ANGGOTA_ERROR]", error);
    throw new Error("Gagal menghapus data anggota");
  }

  revalidatePath("/dashboard/anggota");
}

/**
 * Buat akun login untuk anggota yang belum punya akun
 */
export async function buatAkunAnggota(anggotaId: string, formData: FormData) {
  const session = await auth();
  const loginEmail = formData.get("loginEmail") as string;
  const loginPassword = formData.get("loginPassword") as string;

  if (!loginEmail) throw new Error("Email login wajib diisi");
  if (!loginPassword || loginPassword.length < 8)
    throw new Error("Password minimal 8 karakter");

  const anggota = await prisma.anggota.findUnique({
    where: { id: anggotaId },
    select: { namaLengkap: true, userId: true },
  });
  if (!anggota) throw new Error("Anggota tidak ditemukan");
  if (anggota.userId) throw new Error("Anggota sudah memiliki akun login");

  const existingUser = await prisma.user.findUnique({ where: { email: loginEmail } });
  if (existingUser) throw new Error("Email sudah digunakan akun lain");

  const hashedPassword = await bcrypt.hash(loginPassword, 12);

  let newUserId: string;
  await prisma.$transaction(async (tx) => {
    const user = await tx.user.create({
      data: {
        name: anggota.namaLengkap,
        email: loginEmail,
        password: hashedPassword,
        role: "ANGGOTA",
      },
    });
    newUserId = user.id;
    await tx.anggota.update({
      where: { id: anggotaId },
      data: { userId: user.id },
    });
  });

  // Audit log
  await auditCreate(
    "anggota",
    anggotaId,
    anggota.namaLengkap,
    session?.user?.id,
    session?.user?.name || undefined,
    `Created login account for anggota: ${anggota.namaLengkap} (${loginEmail})`
  );

  revalidatePath("/dashboard/anggota");
  redirect(`/dashboard/anggota/akun/${anggotaId}`);
}

/**
 * Reset password akun anggota
 */
export async function resetPasswordAnggota(userId: string, formData: FormData) {
  const newPassword = formData.get("newPassword") as string;
  if (!newPassword || newPassword.length < 8)
    throw new Error("Password minimal 8 karakter");

  const hashedPassword = await bcrypt.hash(newPassword, 12);

  await prisma.user.update({
    where: { id: userId },
    data: { password: hashedPassword },
  });

  revalidatePath("/dashboard/anggota");
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Eye, EyeOff, Save, AlertCircle, CheckCircle2, Loader2 } from "lucide-react";
import { buatAkunAnggota, resetPasswordAnggota } from "../../actions";
import { toast } from "sonner";

interface Props {
  anggotaId: string;
  userId: string | null;
  mode: "create" | "reset";
  defaultEmail?: string;
}

export default function BuatAkunForm({ anggotaId, userId, mode, defaultEmail = "" }: Props) {
  const router = useRouter();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");
  const [showPassword, setShowPassword] = useState(false);

  const inputCls = "w-full px-4 py-3 rounded-xl border border-slate-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-slate-900 text-sm";

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsSubmitting(true);
    setErrorMsg("");

    const formData = new FormData(e.currentTarget);

    try {
      if (mode === "create") {
        await buatAkunAnggota(anggotaId, formData);
        // redirect() di server action akan melempar NEXT_REDIRECT — tidak perlu toast di sini
      } else {
        await resetPasswordAnggota(userId!, formData);
        toast.success("Password berhasil direset!");
        router.refresh();
        setIsSubmitting(false);
      }
    } catch (error: any) {
      // Re-throw NEXT_REDIRECT agar Next.js bisa handle redirect
      if (error?.digest?.startsWith("NEXT_REDIRECT")) throw error;
      setErrorMsg(error.message || "Terjadi kesalahan");
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {errorMsg && (
        <div className="flex items-start gap-3 p-3 bg-red-50 border border-red-200 rounded-xl text-red-700">
          <AlertCircle className="w-4 h-4 shrink-0 mt-0.5" />
          <p className="text-sm font-semibold">{errorMsg}</p>
        </div>
      )}

      {mode === "create" && (
        <div className="space-y-1.5">
          <label htmlFor="loginEmail" className="text-sm font-bold text-slate-700">
            Email Login <span className="text-red-500">*</span>
          </label>
          <input
            id="loginEmail"
            type="email"
            name="loginEmail"
            required
            defaultValue={defaultEmail}
            placeholder="email@contoh.com"
            className={inputCls}
          />
          <p className="text-[11px] text-slate-400">Digunakan untuk login, harus unik</p>
        </div>
      )}

      <div className="space-y-1.5">
        <label htmlFor={mode === "create" ? "loginPassword" : "newPassword"} className="text-sm font-bold text-slate-700">
          {mode === "create" ? "Password" : "Password Baru"} <span className="text-red-500">*</span>
        </label>
        <div className="relative">
          <input
            id={mode === "create" ? "loginPassword" : "newPassword"}
            type={showPassword ? "text" : "password"}
            name={mode === "create" ? "loginPassword" : "newPassword"}
            required
            minLength={8}
            placeholder="Minimal 8 karakter"
            className={`${inputCls} pr-11`}
          />
          <button
            type="button"
            onClick={() => setShowPassword(!showPassword)}
            className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
          >
            {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
          </button>
        </div>
        <p className="text-[11px] text-slate-400">Minimal 8 karakter</p>
      </div>

      <div className="flex justify-end pt-2">
        <button
          type="submit"
          disabled={isSubmitting}
          className="flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-bold rounded-xl transition-colors disabled:opacity-70 shadow-sm"
        >
          {isSubmitting ? (
            <Loader2 className="w-4 h-4 animate-spin" />
          ) : mode === "create" ? (
            <CheckCircle2 className="w-4 h-4" />
          ) : (
            <Save className="w-4 h-4" />
          )}
          {isSubmitting
            ? "Memproses..."
            : mode === "create"
            ? "Buat Akun"
            : "Simpan Password Baru"}
        </button>
      </div>
    </form>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { useParams, useRouter } from "next/navigation";
import { ChevronLeft, Save, AlertCircle, Loader2 } from "lucide-react";
import { updateAnggota } from "../../actions";
import { toast } from "sonner";
import ThumbnailUpload from "@/components/admin/ThumbnailUpload";

interface Anggota {
  id: string;
  namaLengkap: string;
  nik: string;
  tempatLahir: string | null;
  tanggalLahir: string | null;
  jenisKelamin: "LAKI_LAKI" | "PEREMPUAN";
  alamat: string | null;
  noHp: string | null;
  email: string | null;
  pekerjaan: string | null;
  pendidikan: string | null;
  status: "AKTIF" | "NON_AKTIF" | "ALUMNI";
  foto: string | null;
}

export default function EditAnggotaPage() {
  const params = useParams();
  const router = useRouter();
  const id = params.id as string;

  const [anggota, setAnggota] = useState<Anggota | null>(null);
  const [loading, setLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [errorMsg, setErrorMsg] = useState("");

  useEffect(() => {
    fetch(`/api/anggota/${id}`)
      .then((res) => {
        if (!res.ok) throw new Error("Anggota tidak ditemukan");
        return res.json();
      })
      .then((data) => {
        if (data.tanggalLahir) {
          data.tanggalLahir = new Date(data.tanggalLahir).toISOString().split("T")[0];
        }
        setAnggota(data);
      })
      .catch(() => router.push("/dashboard/anggota"))
      .finally(() => setLoading(false));
  }, [id, router]);

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsSubmitting(true);
    setErrorMsg("");
    const formData = new FormData(e.currentTarget);
    try {
      await updateAnggota(id, formData);
      toast.success("Data anggota berhasil diperbarui!");
    } catch (error: any) {
      setErrorMsg(error.message || "Terjadi kesalahan");
      setIsSubmitting(false);
    }
  };

  const inputCls =
    "w-full px-4 py-3 rounded-xl border border-slate-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-slate-900";

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
      </div>
    );
  }

  if (!anggota) return null;

  return (
    <div className="space-y-6 max-w-4xl">
      <div className="flex items-center gap-4">
        <Link
          href="/dashboard/anggota"
          className="p-2 bg-white rounded-xl border border-slate-200 hover:bg-slate-50 transition-colors shadow-sm"
        >
          <ChevronLeft className="w-5 h-5 text-slate-600" />
        </Link>
        <div>
          <h1 className="text-2xl font-extrabold text-slate-900">Edit Anggota</h1>
          <p className="text-sm text-slate-500 mt-1 line-clamp-1">{anggota.namaLengkap}</p>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 p-6 md:p-8 shadow-sm">
        {errorMsg && (
          <div className="mb-6 p-4 bg-red-50 text-red-700 rounded-xl flex items-start gap-3 border border-red-200">
            <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
            <p className="text-sm font-semibold">{errorMsg}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-8">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
