"use server";

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import bcrypt from "bcryptjs";

export async function createAnggota(formData: FormData) {
  const namaLengkap = formData.get("namaLengkap") as string;
  const nik = formData.get("nik") as string;
  const tempatLahir = formData.get("tempatLahir") as string;
  const tanggalLahir = formData.get("tanggalLahir") as string;
  const jenisKelamin = formData.get("jenisKelamin") as "LAKI_LAKI" | "PEREMPUAN";
  const alamat = formData.get("alamat") as string;
  const noHp = formData.get("noHp") as string;
  const email = formData.get("email") as string;
  const pekerjaan = formData.get("pekerjaan") as string;
  const status = formData.get("status") as "AKTIF" | "NON_AKTIF" | "ALUMNI";
  const foto = formData.get("foto") as string;

  // Akun login (opsional)
  const buatAkun = formData.get("buatAkun") === "true";
  const loginEmail = formData.get("loginEmail") as string;
  const loginPassword = formData.get("loginPassword") as string;

  if (!namaLengkap || !nik || !jenisKelamin) {
    throw new Error("Data tidak lengkap");
  }

  // Validasi akun jika dipilih
  if (buatAkun) {
    if (!loginEmail) throw new Error("Email login wajib diisi");
    if (!loginPassword || loginPassword.length < 8)
      throw new Error("Password minimal 8 karakter");

    const existing = await prisma.user.findUnique({ where: { email: loginEmail } });
    if (existing) throw new Error("Email login sudah digunakan akun lain");
  }

  try {
    if (buatAkun) {
      // Buat User + Anggota sekaligus dalam satu transaksi
      const hashedPassword = await bcrypt.hash(loginPassword, 12);

      await prisma.$transaction(async (tx) => {
        const user = await tx.user.create({
          data: {
            name: namaLengkap,
            email: loginEmail,
            password: hashedPassword,
            role: "ANGGOTA",
          },
        });

        await tx.anggota.create({
          data: {
            userId: user.id,
            namaLengkap,
            nik,
            tempatLahir: tempatLahir || null,
            tanggalLahir: tanggalLahir ? new Date(tanggalLahir) : null,
            jenisKelamin,
            alamat: alamat || null,
            noHp: noHp || null,
            email: email || loginEmail,
            pekerjaan: pekerjaan || null,
            foto: foto || null,
            status,
          },
        });
      });
    } else {
      // Buat Anggota tanpa akun
      await prisma.anggota.create({
        data: {
          namaLengkap,
          nik,
          tempatLahir: tempatLahir || null,
          tanggalLahir: tanggalLahir ? new Date(tanggalLahir) : null,
          jenisKelamin,
          alamat: alamat || null,
          noHp: noHp || null,
          email: email || null,
          pekerjaan: pekerjaan || null,
          foto: foto || null,
          status,
        },
      });
    }
  } catch (error: any) {
    if (error.code === "P2002") throw new Error("NIK sudah terdaftar!");
    throw error;
  }

  revalidatePath("/dashboard/anggota");
  redirect("/dashboard/anggota");
}

"use server";

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { z } from "zod";
import { deleteFileFromStorage } from "@/lib/supabase";
import { auditCreate, auditDelete } from "@/lib/audit";
import { auth } from "@/auth";

const artikelSchema = z.object({
  judul: z.string().min(5, "Judul artikel minimal 5 karakter"),
  kategori: z.string().optional(),
  status: z.enum(["DRAFT", "PUBLISHED", "ARCHIVED"]),
  ringkasan: z.string().optional(),
  isi: z.string().min(10, "Isi artikel tidak boleh kosong"),
});

export async function createArtikel(formData: FormData) {
  const session = await auth();
  const parsed = artikelSchema.safeParse({
    judul: formData.get("judul"),
    kategori: formData.get("kategori"),
    status: formData.get("status"),
    ringkasan: formData.get("ringkasan"),
    isi: formData.get("isi"),
  });

  if (!parsed.success) {
    throw new Error(parsed.error.issues[0].message);
  }

  const { judul, kategori, status, ringkasan, isi } = parsed.data;
  const thumbnail = formData.get("thumbnail") as string;
  const tagsRaw = formData.get("tags") as string;
  let tags: string[] = [];
  try { tags = tagsRaw ? JSON.parse(tagsRaw) : []; } catch {}

  const slug = judul.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)+/g, "") + "-" + Date.now();

  try {
    const artikel = await prisma.artikel.create({
      data: {
        judul,
        slug,
        kategori: kategori || null,
        status,
        ringkasan: ringkasan || null,
        isi,
        thumbnail: thumbnail || null,
        tags,
        publishedAt: status === "PUBLISHED" ? new Date() : null,
      },
    });

    // Audit log
    await auditCreate(
      "artikel",
      artikel.id,
      judul,
      session?.user?.id,
      session?.user?.name || undefined,
      `Created artikel: ${judul} (${status})`
    );
  } catch (error: any) {
    throw new Error("Gagal menyimpan data artikel");
  }

  revalidatePath("/dashboard/artikel");
  redirect("/dashboard/artikel");
}

export async function deleteArtikel(id: string) {
  const session = await auth();

  try {
    // Ambil data artikel untuk hapus thumbnail dari Supabase
    const artikel = await prisma.artikel.findUnique({
      where: { id },
      select: { thumbnail: true, judul: true },
    });

    if (!artikel) {
      throw new Error("Artikel tidak ditemukan");
    }

    // Hapus thumbnail dari Supabase Storage jika ada
    if (artikel.thumbnail) {
      await deleteFileFromStorage(artikel.thumbnail);
    }

    // Hapus data artikel dari database
    await prisma.artikel.delete({ where: { id } });

    // Audit log
    await auditDelete(
      "artikel",
      id,
      artikel.judul,
      session?.user?.id,
      session?.user?.name || undefined,
      `Deleted artikel: ${artikel.judul}`
    );

    revalidatePath("/dashboard/artikel");
    revalidatePath("/");
  } catch (error) {
    console.error("[DELETE_ARTIKEL_ERROR]", error);
    throw new Error("Gagal menghapus artikel");
  }
}

