                      <p className="text-[11px] text-slate-400 mt-0.5">
                        {k._count.transaksi} transaksi
                      </p>
                    </div>
                    <div className="flex items-center gap-1">
                      <Link
                        href={`/dashboard/keuangan/kategori/edit/${k.id}`}
