          {/* Pengeluaran */}
          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            <div className="px-6 py-4 border-b border-slate-100 flex items-center gap-2">
              <div className="w-2.5 h-2.5 rounded-full bg-red-500" />
              <h2 className="text-sm font-bold text-slate-800">
                Kategori Pengeluaran ({keluar.length})
              </h2>
            </div>
            {keluar.length === 0 ? (
              <div className="py-10 text-center">
                <Tag className="w-8 h-8 text-slate-200 mx-auto mb-2" />
                <p className="text-sm text-slate-400">Belum ada kategori pengeluaran</p>
              </div>
            ) : (
              <div className="divide-y divide-slate-50">
                {keluar.map((k) => (
                  <div
                    key={k.id}
                    className="flex items-center justify-between px-6 py-3.5 hover:bg-slate-50/50 transition-colors"
                  >
                    <div>
                      <p className="text-sm font-semibold text-slate-800">{k.nama}</p>
                      {k.keterangan && (
                        <p className="text-xs text-slate-400 mt-0.5">{k.keterangan}</p>
                      )}
                      <p className="text-[11px] text-slate-400 mt-0.5">
                        {k._count.transaksi} transaksi
                      </p>
                    </div>
                    <div className="flex items-center gap-1">
                      <Link
                        href={`/dashboard/keuangan/kategori/edit/${k.id}`}
                        className="p-1.5 text-slate-300 hover:text-amber-500 hover:bg-amber-50 rounded-lg transition-colors"
                      >
                        <Pencil className="w-4 h-4" />
                      </Link>
                      <DeleteKategoriButton
                        id={k.id}
                        nama={k.nama}
                        jumlahTransaksi={k._count.transaksi}
                      />
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { prisma } from "@/lib/prisma";
import { formatCurrency } from "@/lib/utils";
import Link from "next/link";
import { ArrowLeft, TrendingUp, TrendingDown, Wallet, BarChart3 } from "lucide-react";
import LaporanKeuanganCharts from "@/components/admin/LaporanKeuanganCharts";
import ExportKeuanganButton from "@/components/admin/ExportKeuanganButton";

export const metadata = { title: "Laporan Keuangan" };

export default async function LaporanKeuanganPage({
  searchParams,
}: {
  searchParams: Promise<{ tahun?: string }>;
}) {
  const params = await searchParams;
  const tahunAktif = params.tahun ? parseInt(params.tahun) : new Date().getFullYear();

  // Ambil semua transaksi tahun aktif
  const transaksiTahun = await prisma.transaksiKeuangan.findMany({
    where: {
      tanggal: {
        gte: new Date(tahunAktif, 0, 1),
        lt: new Date(tahunAktif + 1, 0, 1),
      },
    },
    include: { kategori: true },
    orderBy: { tanggal: "asc" },
  });

  // Ringkasan per bulan
  const bulanNames = ["Jan", "Feb", "Mar", "Apr", "Mei", "Jun", "Jul", "Agu", "Sep", "Okt", "Nov", "Des"];
  const perBulan = bulanNames.map((nama, idx) => {
    const bulanTransaksi = transaksiTahun.filter(
      (t) => new Date(t.tanggal).getMonth() === idx
    );
    const masuk = bulanTransaksi.filter((t) => t.jenis === "MASUK").reduce((s, t) => s + t.jumlah, 0);
    const keluar = bulanTransaksi.filter((t) => t.jenis === "KELUAR").reduce((s, t) => s + t.jumlah, 0);
    return { nama, masuk, keluar, saldo: masuk - keluar, jumlahTransaksi: bulanTransaksi.length };
  });

  // Total tahun ini
  const totalMasuk = transaksiTahun.filter((t) => t.jenis === "MASUK").reduce((s, t) => s + t.jumlah, 0);
  const totalKeluar = transaksiTahun.filter((t) => t.jenis === "KELUAR").reduce((s, t) => s + t.jumlah, 0);
  const saldoTahun = totalMasuk - totalKeluar;

  // Ringkasan per kategori
  const perKategori: Record<string, { nama: string; masuk: number; keluar: number }> = {};
  transaksiTahun.forEach((t) => {
    const key = t.kategoriId || "umum";
    const nama = t.kategori?.nama || "Umum";
    if (!perKategori[key]) perKategori[key] = { nama, masuk: 0, keluar: 0 };
    if (t.jenis === "MASUK") perKategori[key].masuk += t.jumlah;
    else perKategori[key].keluar += t.jumlah;
  });

  // Tahun tersedia
  const tahunList = Array.from(
    { length: new Date().getFullYear() - 2022 },
    (_, i) => 2023 + i
  );

  return (
    <div className="space-y-6 max-w-5xl">
      {/* Header */}
      <div className="flex items-center gap-4">
        <Link href="/dashboard/keuangan" className="p-2 rounded-xl border border-slate-200 hover:bg-slate-50 transition-colors text-slate-500 shadow-sm">
          <ArrowLeft className="w-4 h-4" />
        </Link>
        <div className="flex-1">
          <h1 className="text-2xl font-extrabold text-slate-900">Laporan Keuangan</h1>
          <p className="text-sm text-slate-400 mt-0.5">Ringkasan arus kas per bulan dan kategori</p>
        </div>
        <div className="flex items-center gap-3">
          {/* Pilih tahun */}
          <div className="flex gap-2">
            {tahunList.map((t) => (
              <Link
                key={t}
                href={`/dashboard/keuangan/laporan?tahun=${t}`}
                className={`px-3 py-2.5 rounded-xl border text-sm font-bold transition-all ${
                  tahunAktif === t
                    ? "bg-blue-600 text-white border-blue-600 shadow-sm"
                    : "bg-white text-slate-700 border-slate-200 hover:bg-slate-50"
                }`}
              >
                {t}
              </Link>
            ))}
          </div>
          <ExportKeuanganButton
            transaksi={transaksiTahun as any}
            totalPemasukan={totalMasuk}
            totalPengeluaran={totalKeluar}
            saldo={saldoTahun}
          />
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-blue-600 rounded-2xl p-6 text-white shadow-sm shadow-blue-500/20">
          <div className="flex items-center gap-2 mb-3">
            <Wallet className="w-4 h-4 text-blue-200" />
            <p className="text-[11px] font-bold uppercase tracking-widest text-blue-200">Saldo Tahun {tahunAktif}</p>
          </div>
          <p className={`text-3xl font-extrabold ${saldoTahun >= 0 ? "text-white" : "text-red-300"}`}>
            {formatCurrency(saldoTahun)}
          </p>
          <p className="text-[11px] text-blue-200 mt-1">{transaksiTahun.length} transaksi</p>
        </div>
        <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
          <div className="flex items-center gap-2 mb-3">
            <TrendingDown className="w-4 h-4 text-emerald-500" />
            <p className="text-[11px] font-bold uppercase tracking-widest text-emerald-600">Total Pemasukan</p>
          </div>
          <p className="text-3xl font-extrabold text-emerald-600">{formatCurrency(totalMasuk)}</p>
        </div>
        <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
          <div className="flex items-center gap-2 mb-3">
            <TrendingUp className="w-4 h-4 text-red-500" />
            <p className="text-[11px] font-bold uppercase tracking-widest text-red-500">Total Pengeluaran</p>
          </div>
          <p className="text-3xl font-extrabold text-red-500">{formatCurrency(totalKeluar)}</p>
        </div>
      </div>

      {/* Chart */}
      <LaporanKeuanganCharts perBulan={perBulan} />

      {/* Tabel per bulan */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 flex items-center gap-2">
          <BarChart3 className="w-4 h-4 text-blue-500" />
          <h2 className="text-sm font-bold text-slate-800">Ringkasan Per Bulan — {tahunAktif}</h2>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-100">
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Bulan</th>
                <th className="text-right text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Pemasukan</th>
                <th className="text-right text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Pengeluaran</th>
                <th className="text-right text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Saldo Bulan</th>
                <th className="text-center text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Transaksi</th>
              </tr>
            </thead>
            <tbody>
              {perBulan.map((b, i) => (
                <tr key={i} className={`border-b border-slate-50 last:border-0 hover:bg-slate-50/50 transition-colors ${b.jumlahTransaksi === 0 ? "opacity-40" : ""}`}>
                  <td className="py-3 px-4 text-sm font-semibold text-slate-800">{b.nama} {tahunAktif}</td>
                  <td className="py-3 px-4 text-right text-sm font-semibold text-emerald-600">
                    {b.masuk > 0 ? `+${formatCurrency(b.masuk)}` : "-"}
                  </td>
                  <td className="py-3 px-4 text-right text-sm font-semibold text-red-500">
                    {b.keluar > 0 ? `-${formatCurrency(b.keluar)}` : "-"}
                  </td>
                  <td className="py-3 px-4 text-right">
                    <span className={`text-sm font-extrabold ${b.saldo >= 0 ? "text-blue-600" : "text-red-500"}`}>
                      {b.saldo !== 0 ? formatCurrency(b.saldo) : "-"}
                    </span>
                  </td>
                  <td className="py-3 px-4 text-center">
                    <span className="text-xs font-bold text-slate-500 bg-slate-100 px-2 py-1 rounded-md">
                      {b.jumlahTransaksi}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
            <tfoot>
              <tr className="bg-slate-50 border-t-2 border-slate-200">
                <td className="py-3 px-4 text-sm font-extrabold text-slate-900">Total</td>
                <td className="py-3 px-4 text-right text-sm font-extrabold text-emerald-600">+{formatCurrency(totalMasuk)}</td>
                <td className="py-3 px-4 text-right text-sm font-extrabold text-red-500">-{formatCurrency(totalKeluar)}</td>
                <td className="py-3 px-4 text-right">
                  <span className={`text-sm font-extrabold ${saldoTahun >= 0 ? "text-blue-600" : "text-red-500"}`}>
                    {formatCurrency(saldoTahun)}
                  </span>
                </td>
                <td className="py-3 px-4 text-center text-sm font-extrabold text-slate-700">{transaksiTahun.length}</td>
              </tr>
            </tfoot>
          </table>
        </div>
      </div>

      {/* Per Kategori */}
      {Object.keys(perKategori).length > 0 && (
        <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
          <div className="px-6 py-4 border-b border-slate-100">
            <h2 className="text-sm font-bold text-slate-800">Ringkasan Per Kategori</h2>
          </div>
          <div className="divide-y divide-slate-50">
            {Object.values(perKategori).map((k, i) => (
              <div key={i} className="flex items-center justify-between px-6 py-3.5 hover:bg-slate-50/50 transition-colors">
                <p className="text-sm font-semibold text-slate-800">{k.nama}</p>
                <div className="flex items-center gap-6 text-sm">
                  {k.masuk > 0 && <span className="font-bold text-emerald-600">+{formatCurrency(k.masuk)}</span>}
                  {k.keluar > 0 && <span className="font-bold text-red-500">-{formatCurrency(k.keluar)}</span>}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

import { prisma } from "@/lib/prisma";
import { formatCurrency, formatDate } from "@/lib/utils";
import { Wallet, Plus, ArrowUpRight, ArrowDownRight, Pencil, Tag, FileImage, BarChart3 } from "lucide-react";
import Link from "next/link";
import DeleteTransaksiButton from "@/components/admin/DeleteTransaksiButton";
import ExportKeuanganButton from "@/components/admin/ExportKeuanganButton";
import Pagination from "@/components/admin/Pagination";

export const metadata = { title: "Keuangan" };

const PER_PAGE = 20;

export default async function KeuanganPage({
  searchParams,
}: {
  searchParams: Promise<{ jenis?: string; bulan?: string; tahun?: string; page?: string }>;
}) {
  const params = await searchParams;
  const jenisFilter = params.jenis ?? "SEMUA";
  const bulanFilter = params.bulan ? parseInt(params.bulan) : null;
  const tahunFilter = params.tahun ? parseInt(params.tahun) : null;
  const page = Math.max(1, parseInt(params.page ?? "1") || 1);

  const where: any = {
    ...(jenisFilter !== "SEMUA" ? { jenis: jenisFilter } : {}),
    ...(bulanFilter && tahunFilter
      ? {
          tanggal: {
            gte: new Date(tahunFilter, bulanFilter - 1, 1),
            lt: new Date(tahunFilter, bulanFilter, 1),
          },
        }
      : tahunFilter
      ? {
          tanggal: {
            gte: new Date(tahunFilter, 0, 1),
            lt: new Date(tahunFilter + 1, 0, 1),
          },
        }
      : {}),
  };

  const transaksiList = await prisma.transaksiKeuangan.findMany({
    where,
    orderBy: { tanggal: "desc" },
    skip: (page - 1) * PER_PAGE,
    take: PER_PAGE,
    include: { kategori: true },
  });

  const totalFiltered = await prisma.transaksiKeuangan.count({ where });
  const totalPages = Math.ceil(totalFiltered / PER_PAGE);
  const baseUrl = `/dashboard/keuangan?jenis=${jenisFilter}${bulanFilter ? `&bulan=${bulanFilter}` : ""}${tahunFilter ? `&tahun=${tahunFilter}` : ""}`;

  // Hitung dari SEMUA transaksi (bukan filtered) untuk summary cards
  const allTransaksi = await prisma.transaksiKeuangan.findMany({
    select: { jumlah: true, jenis: true },
  });
  const totalPemasukan = allTransaksi
    .filter((t) => t.jenis === "MASUK")
    .reduce((sum, t) => sum + t.jumlah, 0);
  const totalPengeluaran = allTransaksi
    .filter((t) => t.jenis === "KELUAR")
    .reduce((sum, t) => sum + t.jumlah, 0);
  const saldo = totalPemasukan - totalPengeluaran;

  // Filtered totals — hitung dari semua data filtered (bukan hanya halaman ini)
  const allFiltered = await prisma.transaksiKeuangan.findMany({
    where,
    select: { jumlah: true, jenis: true },
  });
  const filteredPemasukan = allFiltered
    .filter((t) => t.jenis === "MASUK")
    .reduce((sum, t) => sum + t.jumlah, 0);
  const filteredPengeluaran = allFiltered
    .filter((t) => t.jenis === "KELUAR")
    .reduce((sum, t) => sum + t.jumlah, 0);

  const isFiltered = jenisFilter !== "SEMUA" || bulanFilter || tahunFilter;

  // Tahun tersedia untuk filter
  const tahunList = Array.from(
    { length: new Date().getFullYear() - 2022 },
    (_, i) => 2023 + i
  );
  const bulanList = [
    { value: 1, label: "Januari" }, { value: 2, label: "Februari" },
    { value: 3, label: "Maret" }, { value: 4, label: "April" },
    { value: 5, label: "Mei" }, { value: 6, label: "Juni" },
    { value: 7, label: "Juli" }, { value: 8, label: "Agustus" },
    { value: 9, label: "September" }, { value: 10, label: "Oktober" },
    { value: 11, label: "November" }, { value: 12, label: "Desember" },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-extrabold text-slate-900">Keuangan</h1>
          <p className="text-sm text-slate-500 mt-1">Laporan arus kas dan transparansi dana</p>
        </div>
        <div className="flex items-center gap-3 flex-wrap">
          <ExportKeuanganButton
            transaksi={transaksiList as any}
            totalPemasukan={filteredPemasukan}
            totalPengeluaran={filteredPengeluaran}
            saldo={filteredPemasukan - filteredPengeluaran}
          />
          <Link
            href="/dashboard/keuangan/laporan"
            className="inline-flex items-center gap-2 px-4 py-2.5 border border-slate-200 bg-white hover:bg-slate-50 text-slate-700 text-sm font-bold rounded-xl shadow-sm transition-colors"
          >
            <BarChart3 className="w-4 h-4" />
            Laporan
          </Link>
          <Link
            href="/dashboard/keuangan/kategori"
            className="inline-flex items-center gap-2 px-4 py-2.5 border border-slate-200 bg-white hover:bg-slate-50 text-slate-700 text-sm font-bold rounded-xl shadow-sm transition-colors"
          >
            <Tag className="w-4 h-4" />
            Kelola Kategori
          </Link>
          <Link
            href="/dashboard/keuangan/tambah"
            className="inline-flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-bold rounded-xl shadow-sm transition-colors"
          >
            <Plus className="w-4 h-4" />
            Tambah Transaksi
          </Link>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white rounded-2xl border border-slate-200 p-6 flex flex-col justify-between h-32 shadow-sm">
          <p className="text-sm font-semibold text-slate-600">Saldo Kas Saat Ini</p>
          <p className={`text-3xl font-extrabold ${saldo >= 0 ? "text-blue-600" : "text-red-600"}`}>
            {formatCurrency(saldo)}
          </p>
        </div>
        <div className="bg-emerald-50 rounded-2xl border border-emerald-200 p-6 flex flex-col justify-between h-32">
          <p className="text-sm font-semibold text-emerald-800">Total Pemasukan</p>
          <p className="text-3xl font-extrabold text-emerald-600">{formatCurrency(totalPemasukan)}</p>
        </div>
        <div className="bg-red-50 rounded-2xl border border-red-200 p-6 flex flex-col justify-between h-32">
          <p className="text-sm font-semibold text-red-800">Total Pengeluaran</p>
          <p className="text-3xl font-extrabold text-red-600">{formatCurrency(totalPengeluaran)}</p>
        </div>
      </div>

      {/* Filter */}
      <form method="GET" className="flex flex-wrap gap-3 items-end">
        <div className="space-y-1">
          <label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Jenis</label>
          <select
            name="jenis"
            defaultValue={jenisFilter}
            className="px-3 py-2.5 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all"
          >
            <option value="SEMUA">Semua Jenis</option>
            <option value="MASUK">Pemasukan</option>
            <option value="KELUAR">Pengeluaran</option>
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Bulan</label>
          <select
            name="bulan"
            defaultValue={bulanFilter ?? ""}
            className="px-3 py-2.5 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all"
          >
            <option value="">Semua Bulan</option>
            {bulanList.map((b) => (
              <option key={b.value} value={b.value}>{b.label}</option>
            ))}
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Tahun</label>
          <select
            name="tahun"
            defaultValue={tahunFilter ?? ""}
            className="px-3 py-2.5 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all"
          >
            <option value="">Semua Tahun</option>
            {tahunList.map((t) => (
              <option key={t} value={t}>{t}</option>
            ))}
          </select>
        </div>
        <button
          type="submit"
          className="px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-bold rounded-xl transition-colors shadow-sm"
        >
          Filter
        </button>
        {isFiltered && (
          <Link
            href="/dashboard/keuangan"
            className="px-4 py-2.5 border border-slate-200 bg-white hover:bg-slate-50 text-slate-600 text-sm font-bold rounded-xl transition-colors"
          >
            Reset
          </Link>
        )}
      </form>

      {/* Info filtered */}
      {isFiltered && (
        <div className="flex items-center gap-4 text-sm text-slate-500 bg-blue-50 border border-blue-100 rounded-xl px-4 py-3">
          <span>
            Menampilkan <strong className="text-blue-700">{transaksiList.length}</strong> transaksi
          </span>
          <span>·</span>
          <span>
            Pemasukan: <strong className="text-emerald-600">{formatCurrency(filteredPemasukan)}</strong>
          </span>
          <span>·</span>
          <span>
            Pengeluaran: <strong className="text-red-500">{formatCurrency(filteredPengeluaran)}</strong>
          </span>
        </div>
      )}

      {/* Tabel */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Tanggal</th>
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Keterangan</th>
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Kategori</th>
                <th className="text-right text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Jumlah</th>
                <th className="text-right text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Aksi</th>
              </tr>
            </thead>
            <tbody>
              {transaksiList.length === 0 ? (
                <tr>
                  <td colSpan={5} className="text-center py-12 text-slate-400">
                    <Wallet className="w-10 h-10 mx-auto mb-3 opacity-40" />
                    <p className="text-sm font-medium">Belum ada riwayat transaksi</p>
                  </td>
                </tr>
              ) : (
                transaksiList.map((t: any) => (
                  <tr key={t.id} className="border-b border-slate-100 last:border-0 hover:bg-blue-50/30 transition-colors">
                    <td className="py-3.5 px-4 text-sm text-slate-600">{formatDate(t.tanggal)}</td>
                    <td className="py-3.5 px-4">
                      <p className="text-sm font-semibold text-slate-800">{t.keterangan}</p>
                    </td>
                    <td className="py-3.5 px-4">
                      <span className="text-xs text-slate-600 bg-slate-100 px-2 py-1 rounded-md font-medium">
                        {t.kategori?.nama || "Umum"}
                      </span>
                    </td>
                    <td className="py-3.5 px-4 text-right">
                      {t.jenis === "MASUK" ? (
                        <div className="flex items-center justify-end gap-1.5 text-emerald-600 font-bold text-sm">
                          <ArrowDownRight className="w-4 h-4" />
                          +{formatCurrency(t.jumlah)}
                        </div>
                      ) : (
                        <div className="flex items-center justify-end gap-1.5 text-red-500 font-bold text-sm">
                          <ArrowUpRight className="w-4 h-4" />
                          -{formatCurrency(t.jumlah)}
                        </div>
                      )}
                    </td>
                    <td className="py-3.5 px-4 text-right">
                      <div className="flex items-center justify-end gap-1">
                        {t.bukti && (
                          <a
                            href={t.bukti}
                            target="_blank"
                            rel="noopener noreferrer"
                            title="Lihat bukti transaksi"
                            className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                          >
                            <FileImage className="w-4 h-4" />
                          </a>
                        )}
                        <Link
                          href={`/dashboard/keuangan/edit/${t.id}`}
                          title="Edit Transaksi"
                          aria-label="Edit Transaksi"
                          className="p-2 text-slate-400 hover:text-amber-600 hover:bg-amber-50 rounded-lg transition-colors"
                        >
                          <Pencil className="w-4 h-4" />
                        </Link>
                        <DeleteTransaksiButton id={t.id} keterangan={t.keterangan} />
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
        {totalFiltered > 0 && (
          <div className="px-4 border-t border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-2">
            <p className="text-xs text-slate-500 font-medium py-3">
              Menampilkan {(page - 1) * PER_PAGE + 1}–{Math.min(page * PER_PAGE, totalFiltered)} dari {totalFiltered} transaksi
            </p>
            <Pagination currentPage={page} totalPages={totalPages} baseUrl={baseUrl} />
          </div>
        )}
      </div>
    </div>
  );
}

import { prisma } from "@/lib/prisma";
import Link from "next/link";
import { ArrowLeft, PlusCircle } from "lucide-react";
import { redirect } from "next/navigation";
import { revalidatePath } from "next/cache";
import ThumbnailUpload from "@/components/admin/ThumbnailUpload";

export const metadata = { title: "Tambah Transaksi Keuangan" };

export default async function TambahTransaksiPage() {
  const kategoriList = await prisma.kategoriTransaksi.findMany({
    orderBy: { nama: "asc" },
  });

  async function createTransaksi(formData: FormData) {
    "use server";
    const keterangan = formData.get("keterangan") as string;
    const jumlah = formData.get("jumlah") as string;
    const jenis = formData.get("jenis") as "MASUK" | "KELUAR";
    const tanggal = formData.get("tanggal") as string;
    const kategoriId = formData.get("kategoriId") as string;
    const bukti = formData.get("bukti") as string;

    if (!keterangan || !jumlah || !jenis || !tanggal) {
      throw new Error("Semua field wajib diisi");
    }

    const jumlahNum = parseFloat(jumlah);
    if (isNaN(jumlahNum) || jumlahNum <= 0) {
      throw new Error("Jumlah harus berupa angka positif");
    }

    await prisma.transaksiKeuangan.create({
      data: {
        keterangan,
        jumlah: jumlahNum,
        jenis,
        tanggal: new Date(tanggal),
        kategoriId: kategoriId || null,
        bukti: bukti || null,
      },
    });

    revalidatePath("/dashboard/keuangan");
    redirect("/dashboard/keuangan");
  }

  const inputCls =
    "w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm text-slate-800 font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all";

  return (
    <div className="space-y-6 max-w-2xl">
      <div className="flex items-center gap-4">
        <Link href="/dashboard/keuangan" className="p-2 rounded-xl border border-slate-200 hover:bg-slate-50 transition-colors text-slate-500">
          <ArrowLeft className="w-4 h-4" />
        </Link>
        <div>
          <h1 className="text-2xl font-extrabold text-slate-900">Tambah Transaksi</h1>
          <p className="text-sm text-slate-400 mt-0.5">Catat pemasukan atau pengeluaran kas</p>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-gray-100 p-6">
        <form action={createTransaksi} className="space-y-5">
          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">Jenis Transaksi <span className="text-red-500">*</span></label>
            <select name="jenis" required className={inputCls}>
              <option value="MASUK">Pemasukan</option>
              <option value="KELUAR">Pengeluaran</option>
            </select>
          </div>

          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">Keterangan <span className="text-red-500">*</span></label>
            <input name="keterangan" type="text" required placeholder="Contoh: Iuran anggota bulan Januari" className={inputCls} />
          </div>

          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">Jumlah (Rp) <span className="text-red-500">*</span></label>
            <input name="jumlah" type="number" required min="1" step="1000" placeholder="Contoh: 500000" className={inputCls} />
          </div>

          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">Tanggal Transaksi <span className="text-red-500">*</span></label>
            <input name="tanggal" type="date" required defaultValue={new Date().toISOString().split("T")[0]} className={inputCls} />
          </div>

          <div className="space-y-1.5">
