            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { prisma } from "@/lib/prisma";
import { auth } from "@/auth";
import { redirect } from "next/navigation";
import { formatDateTime } from "@/lib/utils";
import {
  Activity,
  Plus,
  Pencil,
  Trash2,
  ToggleRight,
  LogIn,
  LogOut,
  FileText,
  Search,
} from "lucide-react";
import Pagination from "@/components/admin/Pagination";
import Link from "next/link";

export const metadata = { title: "Log Aktivitas" };

const PER_PAGE = 30;

const actionIcon: Record<string, React.ReactNode> = {
  CREATE: <Plus className="w-3.5 h-3.5" />,
  UPDATE: <Pencil className="w-3.5 h-3.5" />,
  DELETE: <Trash2 className="w-3.5 h-3.5" />,
  TOGGLE: <ToggleRight className="w-3.5 h-3.5" />,
  LOGIN: <LogIn className="w-3.5 h-3.5" />,
  LOGOUT: <LogOut className="w-3.5 h-3.5" />,
  PUBLISH: <FileText className="w-3.5 h-3.5" />,
  ARCHIVE: <FileText className="w-3.5 h-3.5" />,
};

const actionColor: Record<string, string> = {
  CREATE: "bg-green-100 text-green-700",
  UPDATE: "bg-blue-100 text-blue-700",
  DELETE: "bg-red-100 text-red-700",
  TOGGLE: "bg-purple-100 text-purple-700",
  LOGIN: "bg-slate-100 text-slate-600",
  LOGOUT: "bg-slate-100 text-slate-600",
  PUBLISH: "bg-emerald-100 text-emerald-700",
  ARCHIVE: "bg-amber-100 text-amber-700",
};

const moduleColor: Record<string, string> = {
  anggota: "bg-blue-50 text-blue-600",
  kegiatan: "bg-sky-50 text-sky-600",
  keuangan: "bg-emerald-50 text-emerald-600",
  berita: "bg-purple-50 text-purple-600",
  artikel: "bg-violet-50 text-violet-600",
  galeri: "bg-pink-50 text-pink-600",
  voting: "bg-orange-50 text-orange-600",
  aspirasi: "bg-amber-50 text-amber-600",
  admin: "bg-red-50 text-red-600",
  sus: "bg-teal-50 text-teal-600",
  program: "bg-indigo-50 text-indigo-600",
  auth: "bg-slate-50 text-slate-600",
};

export default async function LogAktivitasPage({
  searchParams,
}: {
  searchParams: Promise<{ module?: string; action?: string; q?: string; page?: string }>;
}) {
  const session = await auth();
  if (!session?.user) redirect("/login");
  const role = (session.user as any).role;
  if (role !== "SUPER_ADMIN") redirect("/dashboard");

  const params = await searchParams;
  const moduleFilter = params.module ?? "";
  const actionFilter = params.action ?? "";
  const q = params.q?.trim() ?? "";
  const page = Math.max(1, parseInt(params.page ?? "1") || 1);

  const where: any = {
    ...(moduleFilter ? { module: moduleFilter } : {}),
    ...(actionFilter ? { action: actionFilter } : {}),
    ...(q
      ? {
          OR: [
            { userName: { contains: q, mode: "insensitive" } },
            { targetName: { contains: q, mode: "insensitive" } },
            { detail: { contains: q, mode: "insensitive" } },
          ],
        }
      : {}),
  };

  const [logs, total] = await Promise.all([
    prisma.auditLog.findMany({
      where,
      orderBy: { createdAt: "desc" },
      skip: (page - 1) * PER_PAGE,
      take: PER_PAGE,
    }),
    prisma.auditLog.count({ where }),
  ]);

  const totalPages = Math.ceil(total / PER_PAGE);
  const baseUrl = `/dashboard/log?module=${moduleFilter}&action=${actionFilter}${q ? `&q=${encodeURIComponent(q)}` : ""}`;

  const modules = [
    "anggota", "kegiatan", "keuangan", "berita", "artikel",
    "galeri", "voting", "aspirasi", "admin", "sus", "program", "auth",
  ];
  const actions = ["CREATE", "UPDATE", "DELETE", "TOGGLE", "LOGIN", "LOGOUT", "PUBLISH", "ARCHIVE"];

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-extrabold text-slate-900">Log Aktivitas</h1>
          <p className="text-sm text-slate-400 mt-1">Rekam jejak semua aksi yang dilakukan admin</p>
        </div>
        <div className="flex items-center gap-2 px-3 py-2 bg-amber-50 border border-amber-200 rounded-xl text-xs font-bold text-amber-700">
          <Activity className="w-3.5 h-3.5" />
          Hanya Super Admin
        </div>
      </div>

      {/* Filter */}
      <form
        method="GET"
        className="bg-white rounded-2xl border border-slate-200 shadow-sm p-4 flex flex-wrap gap-3 items-end"
      >
        <div className="flex-1 min-w-[180px] space-y-1">
          <label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Cari</label>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              name="q"
              defaultValue={q}
              type="text"
              placeholder="Nama admin, target, detail..."
              className="w-full pl-9 pr-4 py-2.5 rounded-xl border border-slate-200 text-sm text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all"
            />
          </div>
        </div>
        <div className="space-y-1">
          <label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Modul</label>
          <select
            name="module"
            defaultValue={moduleFilter}
            className="px-3 py-2.5 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all"
          >
            <option value="">Semua Modul</option>
            {modules.map((m) => (
              <option key={m} value={m} className="capitalize">{m}</option>
            ))}
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Aksi</label>
          <select
            name="action"
            defaultValue={actionFilter}
            className="px-3 py-2.5 rounded-xl border border-slate-200 bg-white text-sm font-medium text-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all"
          >
            <option value="">Semua Aksi</option>
            {actions.map((a) => (
              <option key={a} value={a}>{a}</option>
            ))}
          </select>
        </div>
        <button
          type="submit"
          className="px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-bold rounded-xl transition-colors shadow-sm"
        >
          Filter
        </button>
        {(moduleFilter || actionFilter || q) && (
          <Link
            href="/dashboard/log"
            className="px-4 py-2.5 border border-slate-200 bg-white hover:bg-slate-50 text-slate-600 text-sm font-bold rounded-xl transition-colors"
          >
            Reset
          </Link>
        )}
      </form>

      {/* Tabel */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Waktu</th>
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Admin</th>
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Aksi</th>
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Modul</th>
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Target</th>
                <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Detail</th>
              </tr>
            </thead>
            <tbody>
              {logs.length === 0 ? (
                <tr>
                  <td colSpan={6} className="text-center py-16 text-slate-400">
                    <Activity className="w-10 h-10 mx-auto mb-3 opacity-30" />
                    <p className="text-sm font-medium">Belum ada log aktivitas</p>
                  </td>
                </tr>
              ) : (
                logs.map((log) => (
                  <tr
                    key={log.id}
                    className="border-b border-slate-50 last:border-0 hover:bg-slate-50/50 transition-colors"
                  >
                    <td className="py-3 px-4 text-xs text-slate-500 whitespace-nowrap">
                      {formatDateTime(log.createdAt)}
                    </td>
                    <td className="py-3 px-4">
                      <p className="text-sm font-semibold text-slate-800">
                        {log.userName || "System"}
                      </p>
                    </td>
                    <td className="py-3 px-4">
                      <span
                        className={`inline-flex items-center gap-1 px-2 py-1 rounded-lg text-[11px] font-bold ${
                          actionColor[log.action] || "bg-slate-100 text-slate-600"
                        }`}
                      >
                        {actionIcon[log.action]}
                        {log.action}
                      </span>
                    </td>
                    <td className="py-3 px-4">
                      <span
                        className={`px-2 py-1 rounded-lg text-[11px] font-bold capitalize ${
                          moduleColor[log.module] || "bg-slate-100 text-slate-600"
                        }`}
                      >
                        {log.module}
                      </span>
                    </td>
                    <td className="py-3 px-4 text-sm text-slate-600 max-w-[160px] truncate">
                      {log.targetName || log.targetId || "-"}
                    </td>
                    <td className="py-3 px-4 text-xs text-slate-500 max-w-[200px] truncate">
                      {log.detail || "-"}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {total > 0 && (
          <div className="px-4 border-t border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-2">
            <p className="text-xs text-slate-500 font-medium py-3">
              Menampilkan {(page - 1) * PER_PAGE + 1}–{Math.min(page * PER_PAGE, total)} dari {total} log
            </p>
            <Pagination currentPage={page} totalPages={totalPages} baseUrl={baseUrl} />
          </div>
        )}
      </div>
    </div>
  );
}

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { Bell, Send, Trash2, Users, User } from "lucide-react";
import { formatDateTime } from "@/lib/utils";
import DeleteNotifButton from "@/components/admin/DeleteNotifButton";

export const metadata = { title: "Kelola Notifikasi" };

export default async function NotifikasiAdminPage() {
  const anggotaUsers = await prisma.user.findMany({
    where: { role: "ANGGOTA" },
    select: { id: true, name: true, email: true },
    orderBy: { name: "asc" },
  });

  const recentNotifs = await prisma.notification.findMany({
    orderBy: { createdAt: "desc" },
    take: 50,
    include: { user: { select: { name: true, email: true } } },
  });

  async function kirimNotifikasi(formData: FormData) {
    "use server";
    const title = (formData.get("title") as string)?.trim();
    const message = (formData.get("message") as string)?.trim();
    const type = (formData.get("type") as string) || "info";
    const target = formData.get("target") as string; // "ALL" atau userId

    if (!title || !message) throw new Error("Judul dan pesan wajib diisi");

    if (target === "ALL") {
      // Kirim ke semua anggota
      const users = await prisma.user.findMany({
        where: { role: "ANGGOTA" },
        select: { id: true },
      });
      await prisma.notification.createMany({
        data: users.map((u) => ({ title, message, type, userId: u.id })),
      });
    } else {
      // Kirim ke satu user
      await prisma.notification.create({
        data: { title, message, type, userId: target },
      });
    }

    revalidatePath("/dashboard/notifikasi");
  }

  const typeOptions = [
    { value: "info", label: "Info", color: "text-blue-600" },
    { value: "success", label: "Sukses", color: "text-green-600" },
    { value: "warning", label: "Peringatan", color: "text-amber-600" },
    { value: "error", label: "Penting", color: "text-red-600" },
  ];

  const typeBadge: Record<string, string> = {
    info: "bg-blue-100 text-blue-700",
    success: "bg-green-100 text-green-700",
    warning: "bg-amber-100 text-amber-700",
    error: "bg-red-100 text-red-700",
  };

  const inputCls =
    "w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm text-slate-800 font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all";

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-extrabold text-slate-900">Kelola Notifikasi</h1>
        <p className="text-sm text-slate-400 mt-1">Kirim pengumuman dan notifikasi ke anggota</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Form Kirim */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm sticky top-24">
            <h2 className="text-sm font-bold text-slate-800 mb-5 flex items-center gap-2">
              <Send className="w-4 h-4 text-blue-500" />
              Kirim Notifikasi
            </h2>
            <form action={kirimNotifikasi} className="space-y-4">
              <div className="space-y-1.5">
                <label className="text-[12px] font-bold text-slate-600">
                  Tujuan <span className="text-red-500">*</span>
                </label>
                <select name="target" required className={inputCls}>
                  <option value="ALL">📢 Semua Anggota ({anggotaUsers.length} orang)</option>
                  {anggotaUsers.map((u) => (
                    <option key={u.id} value={u.id}>
                      👤 {u.name || u.email}
                    </option>
                  ))}
                </select>
              </div>

              <div className="space-y-1.5">
                <label className="text-[12px] font-bold text-slate-600">
                  Tipe
                </label>
                <select name="type" className={inputCls}>
                  {typeOptions.map((t) => (
                    <option key={t.value} value={t.value}>{t.label}</option>
                  ))}
                </select>
              </div>

              <div className="space-y-1.5">
                <label className="text-[12px] font-bold text-slate-600">
                  Judul <span className="text-red-500">*</span>
                </label>
                <input
                  name="title"
                  type="text"
                  required
                  placeholder="Contoh: Pengumuman Rapat"
                  className={inputCls}
                />
              </div>

              <div className="space-y-1.5">
                <label className="text-[12px] font-bold text-slate-600">
                  Pesan <span className="text-red-500">*</span>
                </label>
                <textarea
                  name="message"
                  required
                  rows={4}
                  placeholder="Tulis isi notifikasi..."
                  className={`${inputCls} resize-none`}
                />
              </div>

              <button
                type="submit"
                className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-blue-600 hover:bg-blue-700 text-white text-sm font-bold rounded-xl transition-colors shadow-sm"
              >
                <Send className="w-4 h-4" />
                Kirim Notifikasi
              </button>
            </form>
          </div>
        </div>

        {/* Riwayat */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
            <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between">
              <h2 className="text-sm font-bold text-slate-800 flex items-center gap-2">
                <Bell className="w-4 h-4 text-slate-500" />
                Riwayat Notifikasi ({recentNotifs.length})
              </h2>
            </div>

            {recentNotifs.length === 0 ? (
              <div className="py-16 text-center">
                <Bell className="w-10 h-10 text-slate-200 mx-auto mb-3" />
                <p className="text-sm text-slate-400 font-medium">Belum ada notifikasi terkirim</p>
              </div>
            ) : (
              <div className="divide-y divide-slate-50">
                {recentNotifs.map((n) => (
                  <div
                    key={n.id}
                    className="flex items-start gap-4 px-6 py-4 hover:bg-slate-50/50 transition-colors"
                  >
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1 flex-wrap">
                        <span
                          className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${
                            typeBadge[n.type] || typeBadge.info
                          }`}
                        >
                          {n.type.toUpperCase()}
                        </span>
                        <span className="text-[11px] text-slate-400 flex items-center gap-1">
                          {n.userId ? (
                            <><User className="w-3 h-3" /> {n.user?.name || n.user?.email || "Anggota"}</>
                          ) : (
                            <><Users className="w-3 h-3" /> Broadcast</>
                          )}
                        </span>
                        <span className={`text-[10px] font-bold ${n.isRead ? "text-slate-400" : "text-blue-600"}`}>
                          {n.isRead ? "Dibaca" : "Belum dibaca"}
                        </span>
                      </div>
                      <p className="text-sm font-bold text-slate-800">{n.title}</p>
                      <p className="text-[12px] text-slate-500 mt-0.5 line-clamp-2">{n.message}</p>
                      <p className="text-[10px] text-slate-400 mt-1">{formatDateTime(n.createdAt)}</p>
                    </div>
                    <DeleteNotifButton id={n.id} />
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { prisma } from "@/lib/prisma";
import { auth } from "@/auth";
import Link from "next/link";
import {
  Users,
  Calendar,
  CheckCircle2,
  Newspaper,
  FileText,
  ChevronRight,
  Plus,
  Check,
  MessageSquare,
  Vote as VoteIcon,
  Wallet,
  Zap,
} from "lucide-react";
import { formatDate } from "@/lib/utils";
import {
  AnggotaStatusChart,
  KegiatanJenisChart,
  KontenTrenChart,
} from "@/components/admin/DashboardCharts";

export const metadata = {
  title: "Dashboard Admin",
};

export default async function AdminDashboard() {
  // Auth is already checked by the parent layout — no redirect here to avoid loops
  const session = await auth();
  const userName = session?.user?.name || "Admin";

  // Fetch data
  const [
    totalAnggota, anggotaAktif, totalKegiatan, totalProgram, totalBerita, totalArtikel,
    recentKegiatan, anggotaNonAktif, anggotaAlumni, kegiatanByJenis, allBerita, allArtikel,
    totalAspirasi, totalPolling, pendingAspirasi, totalSaldo
  ] = await Promise.all([
    prisma.anggota.count(),
    prisma.anggota.count({ where: { status: "AKTIF" } }),
    prisma.kegiatan.count(),
    prisma.program.count(),
    prisma.berita.count({ where: { status: "PUBLISHED" } }),
    prisma.artikel.count({ where: { status: "PUBLISHED" } }),
    prisma.kegiatan.findMany({
      take: 5,
      orderBy: { createdAt: "desc" },
      select: { id: true, nama: true, jenis: true, tanggalMulai: true, status: true, deskripsi: true },
    }),
    prisma.anggota.count({ where: { status: "NON_AKTIF" } }),
    prisma.anggota.count({ where: { status: "ALUMNI" } }),
    prisma.kegiatan.groupBy({ by: ["jenis"], _count: { id: true } }),
    prisma.berita.findMany({
      where: { status: "PUBLISHED" },
      select: { publishedAt: true },
    }),
    prisma.artikel.findMany({
      where: { status: "PUBLISHED" },
      select: { publishedAt: true },
    }),
    prisma.aspirasi.count(),
    prisma.polling.count(),
    prisma.aspirasi.count({ where: { status: "PENDING" } }),
    prisma.transaksiKeuangan.findMany({
      select: { jumlah: true, jenis: true }
    }).then(transactions => 
      transactions.reduce((acc, t) => t.jenis === "MASUK" ? acc + t.jumlah : acc - t.jumlah, 0)
    )
  ]);

  // --- Prepare chart data ---

  // 1. Anggota donut chart
  const anggotaChartData = [
    { name: "Aktif", value: anggotaAktif, color: "#3b82f6" },
    { name: "Non-Aktif", value: anggotaNonAktif, color: "#f59e0b" },
    { name: "Alumni", value: anggotaAlumni, color: "#94a3b8" },
  ].filter((d: any) => d.value > 0);

  // 2. Kegiatan bar chart
  const jenisLabels: Record<string, string> = {
    SOSIAL: "Sosial",
    PENDIDIKAN: "Pendidikan",
    EKONOMI: "Ekonomi",
    OLAHRAGA: "Olahraga",
    SENI_BUDAYA: "Seni & Budaya",
    LAINNYA: "Lainnya",
  };
  const kegiatanChartData = kegiatanByJenis.map((k: any) => ({
    name: jenisLabels[k.jenis] || k.jenis,
    jumlah: k._count.id,
  }));

  // 3. Konten tren area chart (last 6 months)
  const months = Array.from({ length: 6 }, (_, i) => {
    const d = new Date();
    d.setMonth(d.getMonth() - (5 - i));
    return { year: d.getFullYear(), month: d.getMonth() };
  });
  const monthNames = ["Jan", "Feb", "Mar", "Apr", "Mei", "Jun", "Jul", "Agu", "Sep", "Okt", "Nov", "Des"];
  const kontenTrenData = months.map(({ year, month }) => {
    const beritaCount = allBerita.filter((b: any) => {
      if (!b.publishedAt) return false;
      const d = new Date(b.publishedAt);
      return d.getFullYear() === year && d.getMonth() === month;
    }).length;
    const artikelCount = allArtikel.filter((a: any) => {
      if (!a.publishedAt) return false;
      const d = new Date(a.publishedAt);
      return d.getFullYear() === year && d.getMonth() === month;
    }).length;
    return { bulan: `${monthNames[month]} ${year}`, berita: beritaCount, artikel: artikelCount };
  });

  // Server time
  const now = new Date();
  const timeStr = now.toLocaleTimeString("id-ID", {
    hour: "2-digit",
    minute: "2-digit",
    timeZone: "Asia/Jakarta",
  });
  const dateStr = now.toLocaleDateString("id-ID", {
    weekday: "long",
    day: "numeric",
    month: "long",
    year: "numeric",
    timeZone: "Asia/Jakarta",
  });

  const stats = [
    {
      label: "Total Anggota",
      value: totalAnggota,
      icon: Users,
      color: "bg-blue-600 shadow-blue-500/20",
      sub: `✓ ${anggotaAktif} Aktif`,
      subColor: "text-blue-600",
      href: "/dashboard/anggota",
    },
    {
      label: "Keuangan (Saldo)",
      value: new Intl.NumberFormat("id-ID", { style: "currency", currency: "IDR", maximumSignificantDigits: 3 }).format(totalSaldo),
      icon: Wallet,
      color: "bg-green-600 shadow-green-500/20",
      sub: "Saldo saat ini",
      subColor: "text-green-600",
      href: "/dashboard/keuangan",
    },
    {
      label: "Aspirasi Masuk",
      value: totalAspirasi,
      icon: MessageSquare,
      color: "bg-purple-600 shadow-purple-500/20",
      sub: `${pendingAspirasi} Menunggu`,
      subColor: "text-purple-600",
      href: "/dashboard/aspirasi",
    },
    {
      label: "Voting Aktif",
      value: totalPolling,
      icon: VoteIcon,
      color: "bg-orange-600 shadow-orange-500/20",
      sub: "E-Voting digital",
      subColor: "text-orange-600",
      href: "/dashboard/voting",
    },
    {
      label: "Kegiatan",
      value: totalKegiatan,
      icon: Calendar,
      color: "bg-sky-600 shadow-sky-500/20",
      sub: "Total aktivitas",
      subColor: "text-sky-600",
      href: "/dashboard/kegiatan",
    },
  ];

  const quickActions = [
    {
      label: "Tambah Kegiatan",
      desc: "Buat agenda baru",
      href: "/dashboard/kegiatan",
      icon: Calendar,
      color: "bg-blue-100 text-blue-600",
    },
    {
      label: "Buat E-Voting",
      desc: "Mulai pemungutan suara",
      href: "/dashboard/voting",
      icon: VoteIcon,
      color: "bg-orange-100 text-orange-600",
    },
    {
      label: "Update Berita",
      desc: "Publikasi info terbaru",
      href: "/dashboard/berita",
      icon: Newspaper,
      color: "bg-purple-100 text-purple-600",
    },
  ];

  const jenisColor: Record<string, string> = {
    PENDIDIKAN: "bg-blue-100 text-blue-700",
    SOSIAL: "bg-green-100 text-green-700",
    OLAHRAGA: "bg-orange-100 text-orange-700",
    SENI: "bg-purple-100 text-purple-700",
    LINGKUNGAN: "bg-emerald-100 text-emerald-700",
    KEAGAMAAN: "bg-amber-100 text-amber-700",
    LAINNYA: "bg-gray-100 text-gray-700",
  };

  const statusColor: Record<string, string> = {
    RENCANA: "bg-yellow-100 text-yellow-700",
    UPCOMING: "bg-blue-100 text-blue-700",
    ONGOING: "bg-green-100 text-green-700",
    SELESAI: "bg-gray-100 text-gray-600",
    BATAL: "bg-red-100 text-red-700",
  };

  return (
    <div className="space-y-6">
      {/* Welcome Banner */}
      <div className="bg-gradient-to-br from-blue-700 via-blue-600 to-indigo-700 rounded-3xl p-8 md:p-10 text-white relative overflow-hidden shadow-xl shadow-blue-500/20">
        {/* Decorative elements */}
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/4 blur-3xl" />
        <div className="absolute bottom-0 left-0 w-32 h-32 bg-blue-400/20 rounded-full translate-y-1/2 -translate-x-1/2 blur-2xl" />
        <div className="absolute top-1/2 right-10 -translate-y-1/2 w-48 h-48 border border-white/10 rounded-full" />

        <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
          <div className="flex items-center gap-6">
            <div className="w-16 h-16 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center shadow-inner border border-white/30">
              <Zap className="w-8 h-8 text-white fill-white/20" />
            </div>
            <div>
              <h1 className="text-2xl md:text-3xl font-black mb-1 tracking-tight">
                Halo, {userName}!
              </h1>
              <p className="text-blue-100 text-sm font-bold uppercase tracking-widest opacity-80">
                Administrator Panel • Generasi Emas
              </p>
              <div className="flex items-center gap-2 mt-2">
                <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse" />
                <p className="text-blue-200 text-xs font-medium">{dateStr}</p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex flex-col items-end bg-black/10 backdrop-blur-sm rounded-2xl px-6 py-4 border border-white/10">
              <span className="text-[10px] text-blue-200 font-black uppercase tracking-widest mb-1 opacity-60">
                Server Time
              </span>
              <span className="text-2xl font-black tracking-tighter">
                {timeStr} <span className="text-sm font-bold opacity-60 ml-1">WIB</span>
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
        {stats.map((stat) => {
          const Icon = stat.icon;
          return (
            <div
              key={stat.label}
              className="bg-white rounded-3xl border border-slate-100 p-6 flex flex-col justify-between hover:shadow-xl hover:shadow-slate-200/50 transition-all duration-300 group"
            >
              <div className="flex items-start justify-between mb-5">
                <div className={`w-12 h-12 ${stat.color} rounded-2xl flex items-center justify-center shadow-lg transition-transform group-hover:scale-110`}>
                  <Icon className="w-6 h-6 text-white" />
                </div>
                <Link href={stat.href} className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-300 hover:text-blue-600 hover:bg-blue-50 transition-all">
                  <ChevronRight className="w-5 h-5" />
                </Link>
              </div>
              <div>
                <p className="text-3xl font-black text-slate-900 mb-1 tracking-tight">{stat.value}</p>
                <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">{stat.label}</p>
              </div>
              <div className="mt-4 pt-4 border-t border-slate-50 flex items-center justify-between">
                <span className={`text-[11px] font-black uppercase tracking-tight ${stat.subColor}`}>
                  {stat.sub}
                </span>
              </div>
            </div>
          );
        })}
      </div>

      {/* Analytics Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <AnggotaStatusChart data={anggotaChartData} />
        <KegiatanJenisChart data={kegiatanChartData} />
        <KontenTrenChart data={kontenTrenData} />
      </div>

      {/* Bottom Grid: Recent + Quick Actions */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Kegiatan Terbaru */}
        <div className="lg:col-span-2 bg-white rounded-2xl border border-gray-100 p-6">
          <div className="flex items-center justify-between mb-5">
            <h2 className="text-lg font-bold text-slate-900">Kegiatan Terbaru</h2>
            <Link
              href="/dashboard/kegiatan"
              className="text-sm font-semibold text-blue-500 hover:text-blue-600 transition-colors"
            >
              Lihat Semua →
            </Link>
          </div>

          {recentKegiatan.length === 0 ? (
            <div className="text-center py-10 text-slate-400">
              <Calendar className="w-10 h-10 mx-auto mb-3 opacity-40" />
              <p className="text-sm font-medium">Belum ada kegiatan</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-gray-100">
                    <th className="text-left text-[11px] text-slate-400 font-bold uppercase tracking-wider pb-3 px-2">
                      Nama Kegiatan
                    </th>
                    <th className="text-left text-[11px] text-slate-400 font-bold uppercase tracking-wider pb-3 px-2">
                      Jenis
                    </th>
                    <th className="text-left text-[11px] text-slate-400 font-bold uppercase tracking-wider pb-3 px-2">
                      Tanggal
                    </th>
                    <th className="text-left text-[11px] text-slate-400 font-bold uppercase tracking-wider pb-3 px-2">
                      Status
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {recentKegiatan.map((k: any) => (
                    <tr
                      key={k.id}
                      className="border-b border-gray-50 last:border-0 hover:bg-slate-50/50 transition-colors"
                    >
                      <td className="py-3.5 px-2">
                        <p className="text-sm font-semibold text-slate-800">{k.nama}</p>
                        <p className="text-xs text-slate-400 mt-0.5 line-clamp-1">
                          {k.deskripsi || "-"}
                        </p>
                      </td>
                      <td className="py-3.5 px-2">
                        <span
                          className={`inline-block px-2.5 py-1 rounded-lg text-[11px] font-bold ${
                            jenisColor[k.jenis] || jenisColor.LAINNYA
                          }`}
                        >
