}

"use client";

import { useState, useEffect } from "react";
import { User, Lock, Save, Eye, EyeOff, Loader2, CheckCircle2, AlertCircle } from "lucide-react";
import { toast } from "sonner";

export default function ProfilAdminPage() {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [changingPw, setChangingPw] = useState(false);
  const [showOld, setShowOld] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);

  const [profile, setProfile] = useState({
    name: "",
    email: "",
    jabatan: "",
    phone: "",
    role: "",
  });

  const [pw, setPw] = useState({ oldPassword: "", newPassword: "", confirmPassword: "" });

  useEffect(() => {
    fetch("/api/admin/profil")
      .then((r) => r.json())
      .then((data) => {
        setProfile({
          name: data.name || "",
          email: data.email || "",
          jabatan: data.admin?.jabatan || "",
          phone: data.admin?.phone || "",
          role: data.role || "",
        });
      })
      .catch(() => toast.error("Gagal memuat profil"))
      .finally(() => setLoading(false));
  }, []);

  const handleSaveProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const res = await fetch("/api/admin/profil", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: profile.name,
          jabatan: profile.jabatan,
          phone: profile.phone,
        }),
      });
      if (!res.ok) throw new Error((await res.json()).error || "Gagal menyimpan");
      toast.success("Profil berhasil diperbarui");
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    if (pw.newPassword !== pw.confirmPassword) {
      toast.error("Konfirmasi password tidak cocok");
      return;
    }
    if (pw.newPassword.length < 8) {
      toast.error("Password baru minimal 8 karakter");
      return;
    }
    setChangingPw(true);
    try {
      const res = await fetch("/api/admin/profil/password", {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          oldPassword: pw.oldPassword,
          newPassword: pw.newPassword,
        }),
      });
      if (!res.ok) throw new Error((await res.json()).error || "Gagal mengubah password");
      toast.success("Password berhasil diubah");
      setPw({ oldPassword: "", newPassword: "", confirmPassword: "" });
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setChangingPw(false);
    }
  };

  const inputCls =
    "w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm text-slate-800 font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all";

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
      </div>
    );
  }

  const roleLabel: Record<string, string> = {
    SUPER_ADMIN: "Super Admin",
    ADMIN: "Admin",
  };

  return (
    <div className="space-y-6 max-w-2xl">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-extrabold text-slate-900">Profil Saya</h1>
        <p className="text-sm text-slate-400 mt-1">Kelola informasi akun dan keamanan</p>
      </div>

      {/* Avatar + Role */}
      <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm flex items-center gap-5">
        <div className="w-16 h-16 bg-blue-600 text-white rounded-2xl flex items-center justify-center text-2xl font-extrabold shrink-0">
          {profile.name.charAt(0).toUpperCase() || "A"}
        </div>
        <div>
          <p className="text-lg font-extrabold text-slate-900">{profile.name || "Admin"}</p>
          <p className="text-sm text-slate-500">{profile.email}</p>
          <span className="inline-block mt-1.5 px-2.5 py-1 bg-purple-100 text-purple-700 text-[11px] font-bold rounded-lg">
            {roleLabel[profile.role] || profile.role}
          </span>
        </div>
      </div>

      {/* Form Profil */}
      <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
        <h2 className="text-sm font-bold text-slate-800 mb-5 flex items-center gap-2">
          <User className="w-4 h-4 text-blue-500" />
          Informasi Profil
        </h2>
        <form onSubmit={handleSaveProfile} className="space-y-5">
          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">
              Nama Lengkap <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              required
              value={profile.name}
              onChange={(e) => setProfile((p) => ({ ...p, name: e.target.value }))}
              className={inputCls}
            />
          </div>
          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">Email</label>
            <input
              type="email"
              value={profile.email}
              disabled
              className={`${inputCls} bg-slate-50 text-slate-400 cursor-not-allowed`}
            />
            <p className="text-[11px] text-slate-400">Email tidak dapat diubah</p>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[12px] font-bold text-slate-600">Jabatan</label>
              <input
                type="text"
                value={profile.jabatan}
                onChange={(e) => setProfile((p) => ({ ...p, jabatan: e.target.value }))}
                placeholder="Contoh: Sekretaris"
                className={inputCls}
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[12px] font-bold text-slate-600">No. HP</label>
              <input
                type="tel"
                value={profile.phone}
                onChange={(e) => setProfile((p) => ({ ...p, phone: e.target.value }))}
                placeholder="081234567890"
                className={inputCls}
              />
            </div>
          </div>
          <div className="flex justify-end pt-2 border-t border-slate-100">
            <button
              type="submit"
              disabled={saving}
              className="inline-flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-bold rounded-xl shadow-sm transition-colors disabled:opacity-70"
            >
              {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
              {saving ? "Menyimpan..." : "Simpan Profil"}
            </button>
          </div>
        </form>
      </div>

      {/* Ganti Password */}
      <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
        <h2 className="text-sm font-bold text-slate-800 mb-5 flex items-center gap-2">
          <Lock className="w-4 h-4 text-amber-500" />
          Ganti Password
        </h2>
        <form onSubmit={handleChangePassword} className="space-y-5">
          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">
              Password Lama <span className="text-red-500">*</span>
            </label>
            <div className="relative">
              <input
                type={showOld ? "text" : "password"}
                required
                value={pw.oldPassword}
                onChange={(e) => setPw((p) => ({ ...p, oldPassword: e.target.value }))}
                placeholder="Masukkan password saat ini"
                className={`${inputCls} pr-11`}
              />
              <button
                type="button"
                onClick={() => setShowOld((v) => !v)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                {showOld ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">
              Password Baru <span className="text-red-500">*</span>
            </label>
            <div className="relative">
              <input
                type={showNew ? "text" : "password"}
                required
                minLength={8}
                value={pw.newPassword}
                onChange={(e) => setPw((p) => ({ ...p, newPassword: e.target.value }))}
                placeholder="Minimal 8 karakter"
                className={`${inputCls} pr-11`}
              />
              <button
                type="button"
                onClick={() => setShowNew((v) => !v)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                {showNew ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          </div>
          <div className="space-y-1.5">
            <label className="text-[12px] font-bold text-slate-600">
              Konfirmasi Password Baru <span className="text-red-500">*</span>
            </label>
            <div className="relative">
              <input
                type={showConfirm ? "text" : "password"}
                required
                value={pw.confirmPassword}
                onChange={(e) => setPw((p) => ({ ...p, confirmPassword: e.target.value }))}
                placeholder="Ulangi password baru"
                className={`${inputCls} pr-11`}
              />
              <button
                type="button"
                onClick={() => setShowConfirm((v) => !v)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                {showConfirm ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
            {pw.confirmPassword && pw.newPassword !== pw.confirmPassword && (
              <p className="text-[11px] text-red-500 flex items-center gap-1">
                <AlertCircle className="w-3 h-3" /> Password tidak cocok
              </p>
            )}
            {pw.confirmPassword && pw.newPassword === pw.confirmPassword && pw.newPassword.length >= 8 && (
              <p className="text-[11px] text-green-600 flex items-center gap-1">
                <CheckCircle2 className="w-3 h-3" /> Password cocok
              </p>
            )}
          </div>
          <div className="flex justify-end pt-2 border-t border-slate-100">
            <button
              type="submit"
              disabled={changingPw}
              className="inline-flex items-center gap-2 px-5 py-2.5 bg-amber-500 hover:bg-amber-600 text-white text-sm font-bold rounded-xl shadow-sm transition-colors disabled:opacity-70"
            >
              {changingPw ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Lock className="w-4 h-4" />
              )}
              {changingPw ? "Mengubah..." : "Ubah Password"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

"use server";

import { prisma } from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import { deleteFileFromStorage } from "@/lib/supabase";
import { auditDelete, auditCreate } from "@/lib/audit";
import { auth } from "@/auth";

export async function deleteProgram(id: string) {
  const session = await auth();

  try {
    // Ambil data program untuk hapus thumbnail dari Supabase
    const program = await prisma.program.findUnique({
      where: { id },
      select: { thumbnail: true, nama: true },
    });

    if (!program) {
      throw new Error("Program tidak ditemukan");
    }

    // Hapus thumbnail dari Supabase Storage jika ada
    if (program.thumbnail) {
      await deleteFileFromStorage(program.thumbnail);
    }

    // Hapus data program dari database
    await prisma.program.delete({ where: { id } });

    // Audit log
    await auditDelete(
      "program",
      id,
      program.nama,
      session?.user?.id,
      session?.user?.name || undefined,
      `Deleted program: ${program.nama}`
    );

    revalidatePath("/dashboard/program");
    revalidatePath("/");
  } catch (error) {
    console.error("[DELETE_PROGRAM_ERROR]", error);
    throw new Error("Gagal menghapus program");
  }
}

import { z } from "zod";
import { redirect } from "next/navigation";

const programSchema = z.object({
  nama: z.string().min(3, "Nama program minimal 3 karakter"),
  deskripsi: z.string().optional(),
  icon: z.string().optional(),
  thumbnail: z.string().optional(),
  status: z.preprocess((val) => val === "true", z.boolean()),
  urutan: z.preprocess((val) => Number(val), z.number().min(0)),
});

export async function createProgram(formData: FormData) {
  const session = await auth();
  const parsed = programSchema.safeParse({
    nama: formData.get("nama"),
    deskripsi: formData.get("deskripsi"),
    icon: formData.get("icon"),
    thumbnail: formData.get("thumbnail"),
    status: formData.get("status") || "true",
    urutan: formData.get("urutan") || "0",
  });

  if (!parsed.success) {
    throw new Error(parsed.error.issues[0].message);
  }

  const { nama, deskripsi, icon, thumbnail, status, urutan } = parsed.data;

  try {
    const program = await prisma.program.create({
      data: {
        nama,
        deskripsi: deskripsi || null,
        icon: icon || null,
        thumbnail: thumbnail || null,
        status,
        urutan,
      },
    });

    // Audit log
    await auditCreate(
      "program",
      program.id,
      nama,
      session?.user?.id,
      session?.user?.name || undefined,
      `Created program: ${nama}`
    );
  } catch (error: any) {
    throw new Error("Gagal menyimpan data program");
  }

  revalidatePath("/dashboard/program");
  redirect("/dashboard/program");
}

"use client";

import { useState } from "react";
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  Cell,
} from "recharts";
import {
  ClipboardList, TrendingUp, CheckCircle2, AlertTriangle,
  XCircle, Trash2, Download, ExternalLink, Users,
} from "lucide-react";
import * as XLSX from "xlsx";
import { toast } from "sonner";

interface SusResponse {
  id: string;
  responden: string | null;
  score: number;
  kategori: string;
  createdAt: Date;
  q1: number; q2: number; q3: number; q4: number; q5: number;
  q6: number; q7: number; q8: number; q9: number; q10: number;
}

interface Props {
  responses: SusResponse[];
  stats: { total: number; avgScore: number; acceptable: number; marginal: number; notAcceptable: number };
  distribution: { range: string; count: number }[];
  avgPerQ: number[];
  deleteResponse: (id: string) => Promise<void>;
}

const susQuestions = [
  "Sering digunakan", "Terlalu rumit", "Mudah digunakan", "Butuh bantuan teknis",
  "Fungsi terintegrasi", "Banyak ketidakkonsistenan", "Cepat dipelajari",
  "Merepotkan", "Percaya diri menggunakan", "Harus belajar banyak",
];

function getKategoriColor(kategori: string) {
  if (kategori === "Acceptable") return "bg-green-100 text-green-700";
  if (kategori === "Marginal") return "bg-amber-100 text-amber-700";
  return "bg-red-100 text-red-700";
}

function getScoreColor(score: number) {
  if (score >= 71.4) return "text-green-600";
  if (score >= 50.9) return "text-amber-600";
  return "text-red-500";
}

function getGrade(score: number) {
  if (score >= 85) return { grade: "A", label: "Excellent" };
  if (score >= 71.4) return { grade: "B", label: "Good" };
  if (score >= 62.5) return { grade: "C", label: "OK" };
  if (score >= 50.9) return { grade: "D", label: "Poor" };
  return { grade: "F", label: "Awful" };
}

export default function SusDashboard({ responses, stats, distribution, avgPerQ, deleteResponse }: Props) {
  const [deleting, setDeleting] = useState<string | null>(null);
  const [filterKategori, setFilterKategori] = useState<string>("ALL");

  const { grade, label } = getGrade(stats.avgScore);

  const barData = avgPerQ.map((avg, i) => ({
    name: `Q${i + 1}`,
    nilai: parseFloat(avg.toFixed(2)),
    // warna berbeda untuk pertanyaan positif (ganjil) vs negatif (genap)
    positif: (i + 1) % 2 !== 0,
  }));

  const filtered = filterKategori === "ALL"
    ? responses
    : responses.filter((r) => r.kategori === filterKategori);

  const handleDelete = async (id: string, nama: string) => {
    if (!confirm(`Hapus data responden "${nama}"?`)) return;
    setDeleting(id);
    try {
      await deleteResponse(id);
      toast.success("Data berhasil dihapus");
    } catch {
      toast.error("Gagal menghapus data");
    } finally {
      setDeleting(null);
    }
  };

  const exportExcel = () => {
    const data = responses.map((r, i) => ({
      No: i + 1,
      Responden: r.responden || "Anonim",
      Q1: r.q1, Q2: r.q2, Q3: r.q3, Q4: r.q4, Q5: r.q5,
      Q6: r.q6, Q7: r.q7, Q8: r.q8, Q9: r.q9, Q10: r.q10,
      "Skor SUS": r.score.toFixed(2),
      Kategori: r.kategori,
      Tanggal: new Date(r.createdAt).toLocaleDateString("id-ID"),
    }));
    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Data SUS");
    XLSX.writeFile(wb, `SUS_Karang_Taruna_${Date.now()}.xlsx`);
    toast.success("Export berhasil!");
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-extrabold text-slate-900">Kuisioner SUS</h1>
          <p className="text-sm text-slate-500 mt-1">Analisis System Usability Scale website Karang Taruna</p>
        </div>
        <div className="flex items-center gap-3">
          <a
            href="/sus"
            target="_blank"
            className="inline-flex items-center gap-2 px-4 py-2.5 border border-slate-200 bg-white hover:bg-slate-50 text-slate-700 text-sm font-bold rounded-xl transition-colors shadow-sm"
          >
            <ExternalLink className="w-4 h-4" />
            Buka Form
          </a>
          <button
            onClick={exportExcel}
            disabled={stats.total === 0}
            className="inline-flex items-center gap-2 px-4 py-2.5 bg-green-600 hover:bg-green-700 text-white text-sm font-bold rounded-xl transition-colors shadow-sm disabled:opacity-50"
          >
            <Download className="w-4 h-4" />
            Export Excel
          </button>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
        {/* Skor rata-rata — card besar */}
        <div className="col-span-2 lg:col-span-1 bg-blue-600 rounded-2xl p-6 text-white shadow-sm shadow-blue-500/20 flex flex-col justify-between">
          <p className="text-[11px] font-bold uppercase tracking-widest text-blue-200">Rata-rata Skor</p>
          <div>
            <p className="text-5xl font-black mt-2">{stats.avgScore.toFixed(1)}</p>
            <div className="flex items-center gap-2 mt-2">
              <span className="text-2xl font-black">{grade}</span>
              <span className="text-sm font-bold text-blue-200">{label}</span>
            </div>
          </div>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 p-5 shadow-sm flex flex-col justify-between">
          <div className="flex items-center justify-between mb-3">
            <p className="text-[11px] text-slate-500 font-bold uppercase">Total Responden</p>
            <Users className="w-4 h-4 text-slate-400" />
          </div>
          <p className="text-3xl font-extrabold text-slate-900">{stats.total}</p>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 p-5 shadow-sm flex flex-col justify-between">
          <div className="flex items-center justify-between mb-3">
            <p className="text-[11px] text-green-600 font-bold uppercase">Acceptable</p>
            <CheckCircle2 className="w-4 h-4 text-green-500" />
          </div>
          <p className="text-3xl font-extrabold text-green-600">{stats.acceptable}</p>
          <p className="text-[11px] text-slate-400 mt-1">≥ 71.4</p>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 p-5 shadow-sm flex flex-col justify-between">
          <div className="flex items-center justify-between mb-3">
            <p className="text-[11px] text-amber-600 font-bold uppercase">Marginal</p>
            <AlertTriangle className="w-4 h-4 text-amber-500" />
          </div>
          <p className="text-3xl font-extrabold text-amber-600">{stats.marginal}</p>
          <p className="text-[11px] text-slate-400 mt-1">50.9 – 71.4</p>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 p-5 shadow-sm flex flex-col justify-between">
          <div className="flex items-center justify-between mb-3">
            <p className="text-[11px] text-red-500 font-bold uppercase">Not Acceptable</p>
            <XCircle className="w-4 h-4 text-red-400" />
          </div>
          <p className="text-3xl font-extrabold text-red-500">{stats.notAcceptable}</p>
          <p className="text-[11px] text-slate-400 mt-1">{"< 50.9"}</p>
        </div>
      </div>

      {/* Charts */}
      {stats.total > 0 && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          {/* Distribusi Skor */}
          <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
            <h2 className="text-sm font-bold text-slate-800 mb-5 flex items-center gap-2">
              <TrendingUp className="w-4 h-4 text-blue-500" />
              Distribusi Skor
            </h2>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={distribution} barSize={28}>
                <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" />
                <XAxis dataKey="range" tick={{ fontSize: 10, fill: "#94a3b8" }} />
                <YAxis tick={{ fontSize: 10, fill: "#94a3b8" }} allowDecimals={false} />
                <Tooltip
                  contentStyle={{ borderRadius: 12, border: "1px solid #e2e8f0", fontSize: 12 }}
                  formatter={(v) => [`${v} responden`, "Jumlah"]}
                />
                <Bar dataKey="count" fill="#3b82f6" radius={[6, 6, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* Bar chart rata-rata per pertanyaan */}
          <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
            <h2 className="text-sm font-bold text-slate-800 mb-1 flex items-center gap-2">
              <ClipboardList className="w-4 h-4 text-purple-500" />
              Rata-rata per Pertanyaan
            </h2>
            <p className="text-[11px] text-slate-400 mb-5">
              Skala 1–5 &nbsp;·&nbsp;
              <span className="inline-flex items-center gap-1">
                <span className="w-2.5 h-2.5 rounded-sm bg-blue-500 inline-block" /> Pertanyaan positif
              </span>
              &nbsp;·&nbsp;
              <span className="inline-flex items-center gap-1">
                <span className="w-2.5 h-2.5 rounded-sm bg-slate-400 inline-block" /> Pertanyaan negatif
              </span>
            </p>
            <ResponsiveContainer width="100%" height={260}>
              <BarChart
                data={barData}
                layout="vertical"
                margin={{ top: 0, right: 24, left: 8, bottom: 0 }}
                barSize={14}
              >
                <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" horizontal={false} />
                <XAxis
                  type="number"
                  domain={[0, 5]}
                  ticks={[0, 1, 2, 3, 4, 5]}
                  tick={{ fontSize: 10, fill: "#94a3b8" }}
                  axisLine={false}
                  tickLine={false}
                />
                <YAxis
                  type="category"
                  dataKey="name"
                  tick={{ fontSize: 11, fill: "#64748b", fontWeight: 600 }}
                  axisLine={false}
                  tickLine={false}
                  width={28}
                />
                <Tooltip
                  contentStyle={{ borderRadius: 10, border: "1px solid #e2e8f0", fontSize: 12 }}
                  formatter={(v, _name, props: any) => [
                    `${typeof v === 'number' ? v : 0} / 5`,
                    props.payload.positif ? "Pertanyaan Positif" : "Pertanyaan Negatif",
                  ]}
                  labelFormatter={(label) => {
                    const idx = parseInt(String(label).replace("Q", "")) - 1;
                    return susQuestions[idx] || label;
                  }}
                />
                <Bar dataKey="nilai" radius={[0, 4, 4, 0]}>
                  {barData.map((entry, index) => (
                    <Cell
                      key={`cell-${index}`}
                      fill={entry.positif ? "#3b82f6" : "#94a3b8"}
                    />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}

      {/* Tabel Data */}
      <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between gap-4 flex-wrap">
          <h2 className="text-sm font-bold text-slate-800">
            Data Responden ({filtered.length})
          </h2>
          <div className="flex gap-2">
            {["ALL", "Acceptable", "Marginal", "Not Acceptable"].map((k) => (
              <button
                key={k}
                onClick={() => setFilterKategori(k)}
                className={`px-3 py-1.5 rounded-lg text-[11px] font-bold transition-colors ${
                  filterKategori === k
                    ? "bg-blue-600 text-white"
                    : "bg-slate-100 text-slate-600 hover:bg-slate-200"
                }`}
              >
                {k === "ALL" ? "Semua" : k}
              </button>
            ))}
          </div>
        </div>

        {filtered.length === 0 ? (
          <div className="py-16 text-center">
            <ClipboardList className="w-10 h-10 text-slate-200 mx-auto mb-3" />
            <p className="text-sm text-slate-400 font-medium">Belum ada data responden</p>
            <p className="text-xs text-slate-400 mt-1">
              Bagikan link form ke pengguna untuk mulai mengumpulkan data
            </p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-slate-50 border-b border-slate-100">
                  <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Responden</th>
                  {Array.from({ length: 10 }, (_, i) => (
                    <th key={i} className="text-center text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-2">Q{i + 1}</th>
                  ))}
                  <th className="text-center text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Skor</th>
                  <th className="text-center text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Kategori</th>
                  <th className="text-left text-[11px] text-slate-500 font-bold uppercase tracking-wider py-3 px-4">Tanggal</th>
                  <th className="py-3 px-4"></th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((r) => (
                  <tr key={r.id} className="border-b border-slate-50 last:border-0 hover:bg-slate-50/50 transition-colors">
                    <td className="py-3 px-4 text-sm font-semibold text-slate-800">{r.responden || "Anonim"}</td>
                    {[r.q1, r.q2, r.q3, r.q4, r.q5, r.q6, r.q7, r.q8, r.q9, r.q10].map((q, i) => (
                      <td key={i} className="py-3 px-2 text-center text-sm text-slate-600">{q}</td>
                    ))}
                    <td className="py-3 px-4 text-center">
                      <span className={`text-sm font-extrabold ${getScoreColor(r.score)}`}>
                        {r.score.toFixed(1)}
