import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/auth";
import { supabaseAdmin, STORAGE_BUCKET } from "@/lib/supabase";

const MAX_FILE_SIZE = 50 * 1024 * 1024; // 50MB
const ALLOWED_IMAGE_TYPES = ["image/jpeg", "image/png", "image/webp", "image/gif"];
const ALLOWED_VIDEO_TYPES = ["video/mp4", "video/webm", "video/quicktime"];
const ALLOWED_TYPES = [...ALLOWED_IMAGE_TYPES, ...ALLOWED_VIDEO_TYPES];

export async function POST(req: NextRequest) {
  // Auth check
  const session = await auth();
  if (!session?.user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }
  const userRole = (session.user as any).role;
  if (userRole !== "ADMIN" && userRole !== "SUPER_ADMIN") {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  try {
    const formData = await req.formData();
    const file = formData.get("file") as File | null;

    if (!file) {
      return NextResponse.json({ error: "File tidak ditemukan" }, { status: 400 });
    }

    // Validasi ukuran
    if (file.size > MAX_FILE_SIZE) {
      return NextResponse.json(
        { error: "Ukuran file maksimal 50MB" },
        { status: 400 }
      );
    }

    // Validasi tipe
    if (!ALLOWED_TYPES.includes(file.type)) {
      return NextResponse.json(
        { error: "Format file tidak didukung. Gunakan JPG, PNG, WebP, GIF, MP4, WebM, atau MOV." },
        { status: 400 }
      );
    }

    // Tentukan folder berdasarkan tipe
    const isVideo = ALLOWED_VIDEO_TYPES.includes(file.type);
    const folder = isVideo ? "videos" : "photos";

    // Generate nama file unik
    const ext = file.name.split(".").pop()?.toLowerCase() ?? "jpg";
    const timestamp = Date.now();
    const random = Math.random().toString(36).substring(2, 8);
    const fileName = `${folder}/${timestamp}-${random}.${ext}`;

    // Upload ke Supabase Storage
    const arrayBuffer = await file.arrayBuffer();
    const buffer = new Uint8Array(arrayBuffer);

    const { error: uploadError } = await supabaseAdmin.storage
      .from(STORAGE_BUCKET)
      .upload(fileName, buffer, {
        contentType: file.type,
        upsert: false,
      });

    if (uploadError) {
      console.error("Supabase upload error:", uploadError);

      // Pesan error yang lebih informatif
      let userMessage = "Gagal mengupload file";
      if (uploadError.message.includes("Bucket not found")) {
        userMessage =
          'Bucket storage "galeri" belum dibuat. Buka Supabase Dashboard → Storage → New bucket → nama: galeri → centang Public → Save.';
      } else if (uploadError.message.includes("Invalid")) {
        userMessage = "Konfigurasi Supabase tidak valid. Periksa NEXT_PUBLIC_SUPABASE_ANON_KEY di .env";
      } else {
        userMessage = uploadError.message;
      }

      return NextResponse.json({ error: userMessage }, { status: 500 });
    }

    // Ambil public URL
    const { data: urlData } = supabaseAdmin.storage
      .from(STORAGE_BUCKET)
      .getPublicUrl(fileName);

    return NextResponse.json({
      url: urlData.publicUrl,
      path: fileName,
      type: isVideo ? "VIDEO" : "FOTO",
    });
  } catch (error) {
    console.error("Upload error:", error);
    return NextResponse.json({ error: "Terjadi kesalahan server" }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import prisma from "@/lib/prisma";
import { auth } from "@/auth";

// POST — anggota daftar ke kegiatan
export async function POST(req: Request) {
  const session = await auth();
  if (!session?.user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const userId = (session.user as any).id;
  const { kegiatanId } = await req.json();

  if (!kegiatanId) return NextResponse.json({ error: "kegiatanId wajib diisi" }, { status: 400 });

  // Cari anggota berdasarkan userId
  const anggota = await prisma.anggota.findUnique({ where: { userId } });
  if (!anggota) return NextResponse.json({ error: "Data anggota tidak ditemukan" }, { status: 404 });

  // Cek kegiatan masih bisa didaftar
  const kegiatan = await prisma.kegiatan.findUnique({ where: { id: kegiatanId } });
  if (!kegiatan) return NextResponse.json({ error: "Kegiatan tidak ditemukan" }, { status: 404 });
  if (kegiatan.status === "SELESAI" || kegiatan.status === "DIBATALKAN") {
    return NextResponse.json({ error: "Kegiatan sudah tidak bisa didaftar" }, { status: 400 });
  }

  // Cek sudah terdaftar
  const existing = await prisma.anggotaKegiatan.findUnique({
    where: { anggotaId_kegiatanId: { anggotaId: anggota.id, kegiatanId } },
  });
  if (existing) return NextResponse.json({ error: "Sudah terdaftar di kegiatan ini" }, { status: 400 });

  await prisma.anggotaKegiatan.create({
    data: { anggotaId: anggota.id, kegiatanId },
  });

  return NextResponse.json({ success: true });
}

// DELETE — anggota batalkan pendaftaran
export async function DELETE(req: Request) {
  const session = await auth();
  if (!session?.user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const userId = (session.user as any).id;
  const { kegiatanId } = await req.json();

  const anggota = await prisma.anggota.findUnique({ where: { userId } });
  if (!anggota) return NextResponse.json({ error: "Data anggota tidak ditemukan" }, { status: 404 });

  // Hanya bisa batalkan jika kegiatan belum selesai
  const kegiatan = await prisma.kegiatan.findUnique({ where: { id: kegiatanId } });
  if (kegiatan?.status === "SELESAI") {
    return NextResponse.json({ error: "Tidak bisa membatalkan kegiatan yang sudah selesai" }, { status: 400 });
  }

  await prisma.anggotaKegiatan.deleteMany({
    where: { anggotaId: anggota.id, kegiatanId },
  });

  return NextResponse.json({ success: true });
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/auth";
import prisma from "@/lib/prisma";
import { supabaseAdmin } from "@/lib/supabase";

const BUCKET = "galeri";
const MAX_SIZE = 2 * 1024 * 1024; // 2MB
const ALLOWED_TYPES = ["image/jpeg", "image/png", "image/webp"];

export async function POST(req: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const userRole = (session.user as any).role;
    if (userRole !== "ANGGOTA") {
      return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const formData = await req.formData();
    const file = formData.get("file") as File | null;
    const anggotaId = formData.get("anggotaId") as string;

    if (!file || !anggotaId) {
      return NextResponse.json({ error: "File dan anggotaId wajib diisi" }, { status: 400 });
    }

    if (!ALLOWED_TYPES.includes(file.type)) {
      return NextResponse.json({ error: "Format file tidak didukung. Gunakan JPG, PNG, atau WebP" }, { status: 400 });
    }

    if (file.size > MAX_SIZE) {
      return NextResponse.json({ error: "Ukuran file maksimal 2MB" }, { status: 400 });
    }

    // Verify anggota belongs to this user
    const anggota = await prisma.anggota.findUnique({
      where: { id: anggotaId, userId: session.user.id },
      select: { id: true, foto: true },
    });

    if (!anggota) {
      return NextResponse.json({ error: "Data anggota tidak ditemukan" }, { status: 404 });
    }

    // Delete old photo if exists
    if (anggota.foto) {
      const oldPath = anggota.foto.split("/").slice(-2).join("/"); // e.g. "foto-profil/xxx.jpg"
      await supabaseAdmin.storage.from(BUCKET).remove([oldPath]);
    }

    // Upload new photo
    const ext = file.type.split("/")[1];
    const path = `foto-profil/${anggotaId}-${Date.now()}.${ext}`;
    const buffer = Buffer.from(await file.arrayBuffer());

    const { error: uploadError } = await supabaseAdmin.storage
      .from(BUCKET)
      .upload(path, buffer, {
        contentType: file.type,
        upsert: true,
      });

    if (uploadError) {
      console.error("[FOTO_UPLOAD_ERROR]", uploadError);
      return NextResponse.json({ error: "Gagal mengupload foto" }, { status: 500 });
    }

    // Get public URL
    const { data: urlData } = supabaseAdmin.storage.from(BUCKET).getPublicUrl(path);
    const publicUrl = urlData.publicUrl;

    // Update anggota.foto
    await prisma.anggota.update({
      where: { id: anggotaId },
      data: { foto: publicUrl },
    });

    return NextResponse.json({ success: true, url: publicUrl });
  } catch (error) {
    console.error("[FOTO_UPLOAD_ERROR]", error);
    return NextResponse.json({ error: "Terjadi kesalahan" }, { status: 500 });
  }
}

