import { prisma } from "@/lib/prisma";
import { auth } from "@/auth";

// GET — ambil notifikasi milik user yang login
export async function GET() {
  const session = await auth();
  if (!session?.user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const userId = (session.user as any).id;

  const notifs = await prisma.notification.findMany({
    where: { userId },
    orderBy: { createdAt: "desc" },
    take: 20,
  });

  const unreadCount = await prisma.notification.count({
    where: { userId, isRead: false },
  });

  return NextResponse.json({ notifs, unreadCount });
}

// PATCH — tandai semua sebagai sudah dibaca
export async function PATCH() {
  const session = await auth();
  if (!session?.user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  const userId = (session.user as any).id;

  await prisma.notification.updateMany({
    where: { userId, isRead: false },
    data: { isRead: true },
  });

  return NextResponse.json({ success: true });
}

import { auth } from "@/auth";
import { redirect, notFound } from "next/navigation";
import prisma from "@/lib/prisma";
import Link from "next/link";
import { ArrowLeft, Calendar, Eye } from "lucide-react";
import { format } from "date-fns";
import { id as localeId } from "date-fns/locale";

export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const artikel = await prisma.artikel.findUnique({ where: { slug } });
  return { title: artikel?.judul || "Artikel" };
}

export default async function ArtikelDetailPage({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const session = await auth();
  if (!session?.user?.id) redirect("/anggota/login");

  const { slug } = await params;

  const artikel = await prisma.artikel.findUnique({ where: { slug } });

  if (!artikel || artikel.status !== "PUBLISHED") notFound();

  // Increment view count
  await prisma.artikel.update({
    where: { id: artikel.id },
    data: { viewCount: { increment: 1 } },
  });

  const relatedArtikel = await prisma.artikel.findMany({
    where: {
      status: "PUBLISHED",
      id: { not: artikel.id },
      ...(artikel.kategori && { kategori: artikel.kategori }),
    },
    orderBy: { publishedAt: "desc" },
    take: 3,
  });

  return (
    <div className="space-y-6">
      <Link
        href="/member/artikel"
        className="inline-flex items-center gap-2 text-sm font-semibold text-slate-600 hover:text-blue-600 transition-colors"
      >
        <ArrowLeft className="w-4 h-4" />
        Kembali ke Artikel
      </Link>

      <article className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        {artikel.thumbnail && (
          <div className="aspect-video bg-slate-100 overflow-hidden">
            <img src={artikel.thumbnail} alt={artikel.judul} className="w-full h-full object-cover" />
          </div>
        )}

        <div className="p-8">
          <div className="flex items-center gap-4 mb-4">
            {artikel.kategori && (
              <span className="px-3 py-1 rounded-lg bg-purple-100 text-purple-700 text-xs font-bold uppercase">
                {artikel.kategori}
              </span>
            )}
            {artikel.publishedAt && (
              <div className="flex items-center gap-2 text-sm text-slate-500">
                <Calendar className="w-4 h-4" />
                {format(new Date(artikel.publishedAt), "d MMMM yyyy", { locale: localeId })}
              </div>
            )}
            <div className="flex items-center gap-2 text-sm text-slate-500">
              <Eye className="w-4 h-4" />
              {artikel.viewCount + 1} views
            </div>
          </div>

          <h1 className="text-3xl font-bold text-slate-900 mb-4">{artikel.judul}</h1>

          {artikel.ringkasan && (
            <p className="text-lg text-slate-600 mb-6 pb-6 border-b border-slate-200">
              {artikel.ringkasan}
            </p>
          )}

          <div
            className="prose prose-slate max-w-none"
            dangerouslySetInnerHTML={{ __html: artikel.isi }}
          />

          {artikel.tags && artikel.tags.length > 0 && (
            <div className="mt-8 pt-6 border-t border-slate-200 flex flex-wrap gap-2">
              {artikel.tags.map((tag) => (
                <span key={tag} className="px-3 py-1 rounded-full bg-slate-100 text-slate-600 text-xs font-medium">
                  #{tag}
                </span>
              ))}
            </div>
          )}
        </div>
      </article>

      {relatedArtikel.length > 0 && (
        <div>
          <h2 className="text-lg font-bold text-slate-900 mb-4">Artikel Terkait</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {relatedArtikel.map((item) => (
              <Link
                key={item.id}
                href={`/member/artikel/${item.slug}`}
                className="bg-white rounded-xl border border-slate-200 p-4 hover:shadow-md transition-all group"
              >
                <h3 className="font-bold text-sm text-slate-900 mb-2 line-clamp-2 group-hover:text-blue-600 transition-colors">
                  {item.judul}
                </h3>
                {item.publishedAt && (
                  <p className="text-xs text-slate-400">
                    {format(new Date(item.publishedAt), "d MMM yyyy", { locale: localeId })}
                  </p>
                )}
              </Link>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

import { auth } from "@/auth";
import { redirect } from "next/navigation";
import prisma from "@/lib/prisma";
import Link from "next/link";
import { BookOpen, Calendar, Eye, ArrowRight } from "lucide-react";
import { format } from "date-fns";
import { id as localeId } from "date-fns/locale";

export const metadata = {
  title: "Artikel | Portal Anggota",
};

export default async function ArtikelPage({
  searchParams,
}: {
  searchParams: Promise<{ kategori?: string }>;
}) {
  const session = await auth();
  if (!session?.user?.id) redirect("/anggota/login");

  const params = await searchParams;
  const kategoriFilter = params.kategori;

  const artikel = await prisma.artikel.findMany({
    where: {
      status: "PUBLISHED",
      ...(kategoriFilter && { kategori: kategoriFilter }),
    },
    orderBy: { publishedAt: "desc" },
    take: 20,
  });

  const allArtikel = await prisma.artikel.findMany({
    where: { status: "PUBLISHED" },
    select: { kategori: true },
  });
  const categories = Array.from(
    new Set(allArtikel.map((a) => a.kategori).filter(Boolean))
  );

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-3">
          <BookOpen className="w-7 h-7 text-blue-600" />
          Artikel
        </h1>
        <p className="text-sm text-slate-500 mt-1">
          Artikel dan tulisan dari Karang Taruna
        </p>
      </div>

      {/* Filter */}
      {categories.length > 0 && (
        <div className="flex gap-2 flex-wrap">
          <Link
            href="/member/artikel"
            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
              !kategoriFilter
                ? "bg-blue-600 text-white shadow-sm"
                : "bg-white text-slate-600 hover:bg-slate-50 border border-slate-200"
            }`}
          >
            Semua
          </Link>
          {categories.map((kat) => (
            <Link
              key={kat}
              href={`/member/artikel?kategori=${kat}`}
              className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
                kategoriFilter === kat
                  ? "bg-blue-600 text-white shadow-sm"
                  : "bg-white text-slate-600 hover:bg-slate-50 border border-slate-200"
              }`}
            >
              {kat}
            </Link>
          ))}
        </div>
      )}

      {artikel.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {artikel.map((item) => (
            <Link
              key={item.id}
              href={`/member/artikel/${item.slug}`}
              className="bg-white rounded-2xl border border-slate-200 overflow-hidden hover:shadow-lg transition-all group"
            >
              {item.thumbnail ? (
                <div className="aspect-video bg-slate-100 overflow-hidden">
                  <img
                    src={item.thumbnail}
                    alt={item.judul}
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                  />
                </div>
              ) : (
                <div className="aspect-video bg-gradient-to-br from-indigo-500 to-purple-700 flex items-center justify-center">
                  <BookOpen className="w-16 h-16 text-white/30" />
                </div>
              )}

              <div className="p-5">
                <div className="flex items-center gap-3 mb-3">
                  {item.kategori && (
                    <span className="px-2 py-1 rounded-md bg-purple-100 text-purple-700 text-[10px] font-bold uppercase">
                      {item.kategori}
                    </span>
                  )}
                  {item.publishedAt && (
                    <div className="flex items-center gap-1 text-[10px] text-slate-400">
                      <Calendar className="w-3 h-3" />
                      {format(new Date(item.publishedAt), "d MMM yyyy", { locale: localeId })}
                    </div>
                  )}
                </div>

                <h3 className="font-bold text-slate-900 mb-2 line-clamp-2 group-hover:text-blue-600 transition-colors">
                  {item.judul}
                </h3>

                {item.ringkasan && (
                  <p className="text-sm text-slate-600 line-clamp-3 mb-4">
                    {item.ringkasan}
                  </p>
                )}

                <div className="flex items-center justify-between pt-3 border-t border-slate-100">
                  <div className="flex items-center gap-1 text-xs text-slate-400">
                    <Eye className="w-3 h-3" />
                    {item.viewCount} views
                  </div>
                  <div className="flex items-center gap-1 text-xs font-semibold text-blue-600 group-hover:gap-2 transition-all">
                    Baca
                    <ArrowRight className="w-3 h-3" />
                  </div>
                </div>
              </div>
            </Link>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-2xl border border-slate-200 p-12 text-center">
          <BookOpen className="w-16 h-16 text-slate-300 mx-auto mb-4" />
          <p className="text-slate-500 font-medium">Belum ada artikel tersedia</p>
        </div>
      )}
    </div>
  );
}

import { auth } from "@/auth";
import { redirect } from "next/navigation";
import prisma from "@/lib/prisma";
import { revalidatePath } from "next/cache";
import {
  Send,
  MessageSquare,
  Clock,
  CheckCircle2,
  XCircle,
  AlertCircle,
  Plus,
} from "lucide-react";

export const metadata = {
  title: "Papan Aspirasi",
};

export default async function AspirasiPage({
  searchParams,
}: {
  searchParams: Promise<{ success?: string; error?: string }>;
}) {
  const session = await auth();
  if (!session?.user) redirect("/anggota/login");

  const userId = (session.user as any).id;
  const params = await searchParams;

  // Fetch member's own aspirations
  const myAspirasi = await prisma.aspirasi.findMany({
    where: { userId },
    orderBy: { createdAt: "desc" },
  });

  // Server Action: Submit Aspirasi
  async function submitAspirasi(formData: FormData) {
    "use server";

    const session = await auth();
    if (!session?.user) redirect("/anggota/login");
    const userId = (session.user as any).id;

    const judul = formData.get("judul") as string;
    const kategori = formData.get("kategori") as string;
    const pesan = formData.get("pesan") as string;

    if (!judul || !pesan) return;

    try {
      await prisma.aspirasi.create({
        data: {
          userId,
          judul,
          kategori,
          pesan,
        },
      });
      revalidatePath("/member/aspirasi");
    } catch (e) {
      console.error(e);
      // Do not redirect inside catch — throw instead
      throw new Error("Gagal mengirim aspirasi");
    }

    redirect("/member/aspirasi?success=1");
  }

  const statusColor: Record<string, string> = {
    PENDING: "bg-amber-100 text-amber-700",
    DIPROSES: "bg-blue-100 text-blue-700",
    SELESAI: "bg-green-100 text-green-700",
    DITOLAK: "bg-red-100 text-red-700",
  };

  const statusLabel: Record<string, string> = {
    PENDING: "Menunggu",
    DIPROSES: "Diproses",
    SELESAI: "Selesai",
    DITOLAK: "Ditolak",
  };

  return (
    <div className="space-y-6 max-w-5xl">
      {/* Page Header */}
      <div>
        <h1 className="text-2xl font-extrabold text-slate-900">Papan Aspirasi</h1>
        <p className="text-sm text-slate-500 mt-1">
          Sampaikan ide, saran, atau keluhan Anda untuk kemajuan Karang Taruna
        </p>
      </div>

      {/* Alerts */}
      {params.success && (
        <div className="flex items-center gap-3 bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-xl text-sm font-medium">
          <CheckCircle2 className="w-5 h-5 shrink-0" />
          Aspirasi Anda berhasil dikirim! Admin akan segera meninjau.
        </div>
      )}
      {params.error && (
        <div className="flex items-center gap-3 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-xl text-sm font-medium">
          <AlertCircle className="w-5 h-5 shrink-0" />
          Gagal mengirim aspirasi. Silakan coba lagi nanti.
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: Submit Form */}
        <div className="lg:col-span-1">
          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm p-6 sticky top-24">
            <h2 className="text-sm font-bold text-slate-800 mb-5 flex items-center gap-2">
              <Plus className="w-4 h-4 text-blue-500" />
              Kirim Aspirasi Baru
            </h2>
            <form action={submitAspirasi} className="space-y-4">
              <div className="space-y-1.5">
                <label htmlFor="judul" className="text-[12px] font-bold text-slate-600">
                  Judul Aspirasi
                </label>
                <input
                  id="judul"
                  name="judul"
                  type="text"
                  required
                  placeholder="Contoh: Usul Program Kerja"
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm text-slate-800 font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all"
                />
              </div>
              <div className="space-y-1.5">
                <label htmlFor="kategori" className="text-[12px] font-bold text-slate-600">
                  Kategori
                </label>
                <select
                  id="kategori"
                  name="kategori"
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm text-slate-800 font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all"
                >
                  <option value="Saran">Saran</option>
                  <option value="Keluhan">Keluhan</option>
                  <option value="Ide Program">Ide Program</option>
                  <option value="Lainnya">Lainnya</option>
                </select>
              </div>
              <div className="space-y-1.5">
                <label htmlFor="pesan" className="text-[12px] font-bold text-slate-600">
                  Pesan Aspirasi
                </label>
                <textarea
                  id="pesan"
                  name="pesan"
                  rows={5}
                  required
                  placeholder="Ceritakan detail aspirasi Anda..."
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-sm text-slate-800 font-medium focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-400 transition-all resize-none"
                />
              </div>
              <button
                type="submit"
                className="w-full flex items-center justify-center gap-2 px-6 py-3.5 bg-blue-600 hover:bg-blue-700 text-white text-sm font-bold rounded-xl transition-colors shadow-sm shadow-blue-500/20"
              >
                <Send className="w-4 h-4" />
                Kirim Sekarang
              </button>
            </form>
          </div>
        </div>

        {/* Right: Aspirasi List */}
        <div className="lg:col-span-2 space-y-4">
          <h2 className="text-sm font-bold text-slate-800 flex items-center gap-2 mb-2">
            <MessageSquare className="w-4 h-4 text-purple-500" />
            Aspirasi Saya ({myAspirasi.length})
          </h2>

          {myAspirasi.length === 0 ? (
            <div className="bg-white rounded-2xl border border-dashed border-slate-200 p-12 text-center">
              <div className="w-16 h-16 rounded-full bg-slate-50 flex items-center justify-center mx-auto mb-4">
                <MessageSquare className="w-8 h-8 text-slate-300" />
              </div>
              <p className="text-sm font-medium text-slate-500">Anda belum pernah mengirim aspirasi.</p>
            </div>
          ) : (
            myAspirasi.map((asp) => (
              <div key={asp.id} className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden hover:shadow-md transition-shadow">
                <div className="p-6">
                  <div className="flex items-start justify-between gap-4 mb-4">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold ${statusColor[asp.status]}`}>
                          {statusLabel[asp.status]}
                        </span>
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                          {asp.kategori}
                        </span>
                      </div>
                      <h3 className="text-base font-bold text-slate-900">{asp.judul}</h3>
                    </div>
                    <div className="text-right shrink-0">
                      <p className="text-[11px] text-slate-400 font-medium">
                        {new Date(asp.createdAt).toLocaleDateString("id-ID", {
                          day: "numeric",
                          month: "short",
                          year: "numeric",
                        })}
                      </p>
                    </div>
                  </div>

                  <p className="text-sm text-slate-600 bg-slate-50/50 p-4 rounded-xl border border-slate-50 mb-4 whitespace-pre-wrap">
                    {asp.pesan}
                  </p>

                  {asp.balasan && (
                    <div className="mt-4 pt-4 border-t border-slate-50">
                      <div className="flex items-start gap-3">
                        <div className="w-8 h-8 rounded-full bg-blue-100 flex items-center justify-center shrink-0">
                          <CheckCircle2 className="w-4 h-4 text-blue-600" />
                        </div>
                        <div className="flex-1">
                          <p className="text-[11px] font-bold text-blue-600 uppercase mb-1">Balasan Admin</p>
                          <p className="text-sm text-slate-700 italic">"{asp.balasan}"</p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

import { auth } from "@/auth";
import { redirect, notFound } from "next/navigation";
import prisma from "@/lib/prisma";
import Link from "next/link";
import { ArrowLeft, Calendar, Eye } from "lucide-react";
import { format } from "date-fns";
import { id as localeId } from "date-fns/locale";
import ShareButton from "@/components/member/ShareButton";

export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const berita = await prisma.berita.findUnique({
    where: { slug },
  });

  return {
    title: berita?.judul || "Berita",
  };
}

export default async function BeritaDetailPage({
  params,
}: {
  params: Promise<{ slug: string }>;
}) {
  const session = await auth();
  if (!session?.user?.id) redirect("/anggota/login");

  const { slug } = await params;
  const berita = await prisma.berita.findUnique({
    where: { slug },
  });

  if (!berita || berita.status !== "PUBLISHED") {
    notFound();
  }

  // Increment view count
  await prisma.berita.update({
    where: { id: berita.id },
    data: { viewCount: { increment: 1 } },
  });

  // Get related berita
  const relatedBerita = await prisma.berita.findMany({
    where: {
      status: "PUBLISHED",
      id: { not: berita.id },
      ...(berita.kategori && { kategori: berita.kategori }),
    },
    orderBy: { publishedAt: "desc" },
    take: 3,
  });

  return (
    <div className="space-y-6">
      {/* Back Button */}
      <Link
        href="/member/berita"
        className="inline-flex items-center gap-2 text-sm font-semibold text-slate-600 hover:text-blue-600 transition-colors"
      >
        <ArrowLeft className="w-4 h-4" />
        Kembali ke Berita
      </Link>

      {/* Article */}
      <article className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
        {/* Thumbnail */}
        {berita.thumbnail && (
          <div className="aspect-video bg-slate-100 overflow-hidden">
            <img
              src={berita.thumbnail}
              alt={berita.judul}
              className="w-full h-full object-cover"
            />
          </div>
        )}

        {/* Content */}
        <div className="p-8">
          {/* Meta */}
          <div className="flex items-center gap-4 mb-4">
            {berita.kategori && (
              <span className="px-3 py-1 rounded-lg bg-blue-100 text-blue-700 text-xs font-bold uppercase">
                {berita.kategori}
              </span>
            )}
            {berita.publishedAt && (
              <div className="flex items-center gap-2 text-sm text-slate-500">
                <Calendar className="w-4 h-4" />
                {format(new Date(berita.publishedAt), "d MMMM yyyy", {
                  locale: localeId,
                })}
              </div>
            )}
            <div className="flex items-center gap-2 text-sm text-slate-500">
              <Eye className="w-4 h-4" />
              {berita.viewCount + 1} views
            </div>
          </div>

          {/* Title */}
          <h1 className="text-3xl font-bold text-slate-900 mb-4">
            {berita.judul}
          </h1>

          {/* Ringkasan */}
          {berita.ringkasan && (
            <p className="text-lg text-slate-600 mb-6 pb-6 border-b border-slate-200">
              {berita.ringkasan}
            </p>
          )}

          {/* Content */}
          <div
            className="prose prose-slate max-w-none"
            dangerouslySetInnerHTML={{ __html: berita.isi }}
          />

          {/* Tags */}
          {berita.tags && berita.tags.length > 0 && (
            <div className="mt-8 pt-6 border-t border-slate-200">
              <div className="flex flex-wrap gap-2">
                {berita.tags.map((tag) => (
                  <span
                    key={tag}
                    className="px-3 py-1 rounded-full bg-slate-100 text-slate-600 text-xs font-medium"
                  >
                    #{tag}
                  </span>
                ))}
              </div>
            </div>
          )}

          {/* Share */}
          <div className="mt-6 pt-6 border-t border-slate-200">
            <ShareButton
              title={berita.judul}
              url={`/member/berita/${berita.slug}`}
            />
          </div>
        </div>
      </article>

      {/* Related Berita */}
      {relatedBerita.length > 0 && (
        <div>
          <h2 className="text-lg font-bold text-slate-900 mb-4">
            Berita Terkait
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {relatedBerita.map((item) => (
              <Link
                key={item.id}
                href={`/member/berita/${item.slug}`}
                className="bg-white rounded-xl border border-slate-200 p-4 hover:shadow-md transition-all group"
              >
                <h3 className="font-bold text-sm text-slate-900 mb-2 line-clamp-2 group-hover:text-blue-600 transition-colors">
                  {item.judul}
                </h3>
                {item.publishedAt && (
                  <p className="text-xs text-slate-400">
                    {format(new Date(item.publishedAt), "d MMM yyyy", {
                      locale: localeId,
                    })}
                  </p>
                )}
              </Link>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

import { auth } from "@/auth";
import { redirect } from "next/navigation";
import prisma from "@/lib/prisma";
import Link from "next/link";
import { Newspaper, Calendar, Eye, ArrowRight } from "lucide-react";
import { format } from "date-fns";
import { id as localeId } from "date-fns/locale";

export const metadata = {
  title: "Berita & Artikel | Portal Anggota",
};

export default async function BeritaPage({
  searchParams,
}: {
  searchParams: Promise<{ kategori?: string }>;
}) {
  const session = await auth();
  if (!session?.user?.id) redirect("/anggota/login");

  const params = await searchParams;
  const kategoriFilter = params.kategori;

  // Fetch berita
  const berita = await prisma.berita.findMany({
    where: {
      status: "PUBLISHED",
      ...(kategoriFilter && { kategori: kategoriFilter }),
    },
    orderBy: { publishedAt: "desc" },
    take: 20,
  });

  // Get unique categories
  const allBerita = await prisma.berita.findMany({
    where: { status: "PUBLISHED" },
    select: { kategori: true },
  });
  const categories = Array.from(
    new Set(allBerita.map((b) => b.kategori).filter(Boolean))
  );

  return (
    <div className="space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-3">
          <Newspaper className="w-7 h-7 text-blue-600" />
          Berita & Artikel
        </h1>
        <p className="text-sm text-slate-500 mt-1">
          Informasi terbaru seputar kegiatan Karang Taruna
        </p>
      </div>

      {/* Filter Kategori */}
      {categories.length > 0 && (
        <div className="flex gap-2 flex-wrap">
          <Link
            href="/member/berita"
            className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
              !kategoriFilter
                ? "bg-blue-600 text-white shadow-sm"
                : "bg-white text-slate-600 hover:bg-slate-50 border border-slate-200"
            }`}
          >
            Semua
          </Link>
          {categories.map((kat) => (
            <Link
              key={kat}
              href={`/member/berita?kategori=${kat}`}
              className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
                kategoriFilter === kat
                  ? "bg-blue-600 text-white shadow-sm"
                  : "bg-white text-slate-600 hover:bg-slate-50 border border-slate-200"
              }`}
            >
              {kat}
            </Link>
          ))}
        </div>
      )}

      {/* Berita Grid */}
      {berita.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {berita.map((item) => (
            <Link
              key={item.id}
              href={`/member/berita/${item.slug}`}
              className="bg-white rounded-2xl border border-slate-200 overflow-hidden hover:shadow-lg transition-all group"
            >
              {/* Thumbnail */}
              {item.thumbnail ? (
                <div className="aspect-video bg-slate-100 overflow-hidden">
                  <img
                    src={item.thumbnail}
                    alt={item.judul}
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                  />
                </div>
              ) : (
                <div className="aspect-video bg-gradient-to-br from-blue-500 to-blue-700 flex items-center justify-center">
                  <Newspaper className="w-16 h-16 text-white/30" />
                </div>
              )}

              {/* Content */}
              <div className="p-5">
                {/* Kategori & Date */}
                <div className="flex items-center gap-3 mb-3">
                  {item.kategori && (
                    <span className="px-2 py-1 rounded-md bg-blue-100 text-blue-700 text-[10px] font-bold uppercase">
                      {item.kategori}
                    </span>
                  )}
                  {item.publishedAt && (
                    <div className="flex items-center gap-1 text-[10px] text-slate-400">
                      <Calendar className="w-3 h-3" />
                      {format(new Date(item.publishedAt), "d MMM yyyy", {
                        locale: localeId,
                      })}
                    </div>
                  )}
                </div>

                {/* Title */}
                <h3 className="font-bold text-slate-900 mb-2 line-clamp-2 group-hover:text-blue-600 transition-colors">
                  {item.judul}
                </h3>

                {/* Ringkasan */}
                {item.ringkasan && (
                  <p className="text-sm text-slate-600 line-clamp-3 mb-4">
                    {item.ringkasan}
                  </p>
                )}

                {/* Footer */}
                <div className="flex items-center justify-between pt-3 border-t border-slate-100">
                  <div className="flex items-center gap-1 text-xs text-slate-400">
                    <Eye className="w-3 h-3" />
                    {item.viewCount} views
                  </div>
                  <div className="flex items-center gap-1 text-xs font-semibold text-blue-600 group-hover:gap-2 transition-all">
                    Baca
                    <ArrowRight className="w-3 h-3" />
                  </div>
                </div>
              </div>
            </Link>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-2xl border border-slate-200 p-12 text-center">
          <Newspaper className="w-16 h-16 text-slate-300 mx-auto mb-4" />
          <p className="text-slate-500 font-medium">
            Belum ada berita untuk kategori ini
          </p>
        </div>
      )}
    </div>
  );
}

