      aria-label="Hapus Transaksi"
      className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors disabled:opacity-50"
    >
      {loading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
    </button>
  );
}

"use client";

import { useState } from "react";
import { Download, FileSpreadsheet, FileText, ChevronDown } from "lucide-react";
import * as XLSX from "xlsx";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import { toast } from "sonner";

interface Peserta {
  id: string;
  hadir: boolean;
  createdAt: Date;
  anggota: {
    namaLengkap: string;
    nik: string;
    noHp: string | null;
  };
}

interface Props {
  namaKegiatan: string;
  tanggal: string;
  peserta: Peserta[];
}

export default function ExportAbsensiButton({ namaKegiatan, tanggal, peserta }: Props) {
  const [open, setOpen] = useState(false);

  const rows = peserta.map((p, i) => ({
    no: i + 1,
    nama: p.anggota.namaLengkap,
    nik: p.anggota.nik,
    noHp: p.anggota.noHp || "-",
    hadir: p.hadir ? "Hadir" : "Tidak Hadir",
    tanda: p.hadir ? "✓" : "✗",
  }));

  const totalHadir = peserta.filter((p) => p.hadir).length;

  const exportExcel = () => {
    const data = rows.map((r) => ({
      No: r.no,
      "Nama Lengkap": r.nama,
      NIK: r.nik,
      "No. HP": r.noHp,
      Kehadiran: r.hadir,
    }));

    data.push({} as any);
    data.push({
      No: "" as any,
      "Nama Lengkap": `Total Hadir: ${totalHadir} / ${peserta.length}`,
      NIK: "",
      "No. HP": "",
      Kehadiran: "",
    });

    const ws = XLSX.utils.json_to_sheet(data);
    ws["!cols"] = [{ wch: 5 }, { wch: 30 }, { wch: 18 }, { wch: 16 }, { wch: 14 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Daftar Hadir");
    XLSX.writeFile(wb, `Absensi_${namaKegiatan.replace(/\s+/g, "_")}_${Date.now()}.xlsx`);
    toast.success("Export Excel berhasil!");
    setOpen(false);
  };

  const exportPDF = () => {
    const doc = new jsPDF();

    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.text("DAFTAR HADIR KEGIATAN", doc.internal.pageSize.width / 2, 18, { align: "center" });
    doc.setFontSize(11);
    doc.text(namaKegiatan, doc.internal.pageSize.width / 2, 26, { align: "center" });
    doc.setFontSize(9);
    doc.setFont("helvetica", "normal");
    doc.text(`Tanggal: ${tanggal}`, doc.internal.pageSize.width / 2, 33, { align: "center" });
    doc.text(
      `Total Hadir: ${totalHadir} dari ${peserta.length} peserta`,
      doc.internal.pageSize.width / 2,
      39,
      { align: "center" }
    );

    autoTable(doc, {
      startY: 45,
      head: [["No", "Nama Lengkap", "NIK", "No. HP", "Kehadiran", "Tanda Tangan"]],
      body: rows.map((r) => [r.no, r.nama, r.nik, r.noHp, r.hadir, ""]),
      styles: { fontSize: 8, cellPadding: 3 },
      headStyles: { fillColor: [37, 99, 235], textColor: 255, fontStyle: "bold" },
      alternateRowStyles: { fillColor: [248, 250, 252] },
      columnStyles: {
        0: { halign: "center", cellWidth: 10 },
        4: { halign: "center" },
        5: { cellWidth: 30 },
      },
    });

    doc.save(`Absensi_${namaKegiatan.replace(/\s+/g, "_")}_${Date.now()}.pdf`);
    toast.success("Export PDF berhasil!");
    setOpen(false);
  };

  return (
    <div className="relative">
      <button
        onClick={() => setOpen((v) => !v)}
        disabled={peserta.length === 0}
        className="inline-flex items-center gap-2 px-4 py-2.5 border border-slate-200 bg-white hover:bg-slate-50 text-slate-700 text-sm font-bold rounded-xl shadow-sm transition-colors disabled:opacity-50"
      >
        <Download className="w-4 h-4" />
        Export Absensi
        <ChevronDown className={`w-3.5 h-3.5 transition-transform ${open ? "rotate-180" : ""}`} />
      </button>

      {open && (
        <>
          <div className="fixed inset-0 z-10" onClick={() => setOpen(false)} />
          <div className="absolute right-0 top-full mt-2 w-44 bg-white border border-slate-200 rounded-xl shadow-lg z-20 overflow-hidden">
            <button
              onClick={exportExcel}
              className="w-full flex items-center gap-3 px-4 py-3 text-sm font-semibold text-slate-700 hover:bg-slate-50 transition-colors"
            >
              <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
              Export Excel
            </button>
            <button
              onClick={exportPDF}
              className="w-full flex items-center gap-3 px-4 py-3 text-sm font-semibold text-slate-700 hover:bg-slate-50 transition-colors border-t border-slate-100"
            >
              <FileText className="w-4 h-4 text-red-500" />
              Export PDF
            </button>
          </div>
        </>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { Download, FileSpreadsheet, FileText, Loader2 } from "lucide-react";
import * as XLSX from "xlsx";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

interface ExportAnggotaButtonProps {
  data: any[];
}

export function ExportAnggotaButton({ data }: ExportAnggotaButtonProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const formatDataForExport = () => {
    return data.map((a: any, index: number) => ({
      No: index + 1,
      NIK: a.nik,
      "Nama Lengkap": a.namaLengkap,
      "Jenis Kelamin": a.jenisKelamin === "LAKI_LAKI" ? "Laki-laki" : "Perempuan",
      "No HP": a.noHp || "-",
      Email: a.email || "-",
      Pekerjaan: a.pekerjaan || "-",
      Status: a.status.replace("_", " "),
      "Tanggal Gabung": new Date(a.tanggalGabung).toLocaleDateString("id-ID"),
    }));
  };

  const exportToExcel = () => {
    setIsExporting(true);
    try {
      const formattedData = formatDataForExport();
      const worksheet = XLSX.utils.json_to_sheet(formattedData);
      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, "Data Anggota");
      XLSX.writeFile(workbook, `Data_Anggota_Karang_Taruna_${new Date().getTime()}.xlsx`);
    } catch (error) {
      console.error("Gagal export Excel:", error);
    } finally {
      setIsExporting(false);
      setIsOpen(false);
    }
  };

  const exportToPDF = () => {
    setIsExporting(true);
    try {
      const doc = new jsPDF("landscape");

      doc.setFontSize(16);
      doc.text("Laporan Data Anggota Karang Taruna", 14, 15);
      doc.setFontSize(10);
      doc.text(`Dicetak pada: ${new Date().toLocaleString("id-ID")}`, 14, 22);

      const formattedData = formatDataForExport();
      const tableColumn = Object.keys(formattedData[0]);
      const tableRows = formattedData.map(obj => Object.values(obj));

      autoTable(doc, {
        head: [tableColumn],
        body: tableRows,
        startY: 28,
        theme: 'grid',
        styles: { fontSize: 8 },
        headStyles: { fillColor: [59, 130, 246] }
      });

      doc.save(`Data_Anggota_Karang_Taruna_${new Date().getTime()}.pdf`);
    } catch (error) {
      console.error("Gagal export PDF:", error);
    } finally {
      setIsExporting(false);
      setIsOpen(false);
    }
  };

  return (
    <div className="relative inline-block text-left">
      <button
        onClick={() => setIsOpen(!isOpen)}
        disabled={isExporting}
        className="inline-flex items-center gap-2 px-5 py-2.5 bg-white border border-gray-200 hover:bg-gray-50 text-slate-700 text-sm font-bold rounded-xl shadow-sm transition-colors disabled:opacity-50"
      >
        {isExporting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Download className="w-4 h-4" />}
        Export Laporan
      </button>

      {isOpen && (
        <>
          <div 
            className="fixed inset-0 z-10" 
            onClick={() => setIsOpen(false)}
          ></div>
          <div className="absolute right-0 mt-2 w-48 bg-white rounded-xl shadow-lg border border-gray-100 z-20 overflow-hidden">
            <button
              onClick={exportToExcel}
              className="w-full text-left px-4 py-3 text-sm font-semibold text-slate-700 hover:bg-green-50 hover:text-green-700 flex items-center gap-2 transition-colors"
            >
              <FileSpreadsheet className="w-4 h-4 text-green-600" />
              Export ke Excel
            </button>
            <button
              onClick={exportToPDF}
              className="w-full text-left px-4 py-3 text-sm font-semibold text-slate-700 hover:bg-red-50 hover:text-red-700 flex items-center gap-2 transition-colors"
            >
              <FileText className="w-4 h-4 text-red-600" />
              Export ke PDF
            </button>
          </div>
        </>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { Download, FileSpreadsheet, FileText, ChevronDown } from "lucide-react";
import * as XLSX from "xlsx";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import { toast } from "sonner";
import { formatCurrency } from "@/lib/utils";

interface Transaksi {
  id: string;
  tanggal: Date;
  keterangan: string;
  jumlah: number;
  jenis: "MASUK" | "KELUAR";
  kategori: { nama: string } | null;
}

interface Props {
  transaksi: Transaksi[];
  totalPemasukan: number;
  totalPengeluaran: number;
  saldo: number;
}

export default function ExportKeuanganButton({
  transaksi,
  totalPemasukan,
  totalPengeluaran,
  saldo,
}: Props) {
  const [open, setOpen] = useState(false);

  const rows = transaksi.map((t, i) => ({
    no: i + 1,
    tanggal: new Date(t.tanggal).toLocaleDateString("id-ID", {
      day: "2-digit",
      month: "long",
      year: "numeric",
    }),
    keterangan: t.keterangan,
    kategori: t.kategori?.nama || "Umum",
    jenis: t.jenis === "MASUK" ? "Pemasukan" : "Pengeluaran",
    jumlah: t.jumlah,
    jumlahFmt: formatCurrency(t.jumlah),
  }));

  const exportExcel = () => {
    const data = rows.map((r) => ({
      No: r.no,
      Tanggal: r.tanggal,
      Keterangan: r.keterangan,
      Kategori: r.kategori,
      Jenis: r.jenis,
      "Jumlah (Rp)": r.jumlah,
    }));

    // Tambah baris ringkasan
    data.push({} as any);
    data.push({ No: "" as any, Tanggal: "RINGKASAN", Keterangan: "", Kategori: "", Jenis: "", "Jumlah (Rp)": "" as any });
    data.push({ No: "" as any, Tanggal: "Total Pemasukan", Keterangan: "", Kategori: "", Jenis: "", "Jumlah (Rp)": totalPemasukan });
    data.push({ No: "" as any, Tanggal: "Total Pengeluaran", Keterangan: "", Kategori: "", Jenis: "", "Jumlah (Rp)": totalPengeluaran });
    data.push({ No: "" as any, Tanggal: "Saldo Akhir", Keterangan: "", Kategori: "", Jenis: "", "Jumlah (Rp)": saldo });

    const ws = XLSX.utils.json_to_sheet(data);
    ws["!cols"] = [{ wch: 5 }, { wch: 20 }, { wch: 35 }, { wch: 18 }, { wch: 14 }, { wch: 18 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Laporan Keuangan");
    XLSX.writeFile(wb, `Laporan_Keuangan_${Date.now()}.xlsx`);
    toast.success("Export Excel berhasil!");
    setOpen(false);
  };

  const exportPDF = () => {
    const doc = new jsPDF({ orientation: "landscape" });

    // Header
    doc.setFontSize(16);
    doc.setFont("helvetica", "bold");
    doc.text("LAPORAN KEUANGAN", doc.internal.pageSize.width / 2, 18, { align: "center" });
    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text("Karang Taruna Generasi Emas", doc.internal.pageSize.width / 2, 25, { align: "center" });
    doc.text(
      `Dicetak: ${new Date().toLocaleDateString("id-ID", { day: "numeric", month: "long", year: "numeric" })}`,
      doc.internal.pageSize.width / 2,
      31,
      { align: "center" }
    );

    // Tabel transaksi
    autoTable(doc, {
      startY: 38,
      head: [["No", "Tanggal", "Keterangan", "Kategori", "Jenis", "Jumlah (Rp)"]],
      body: rows.map((r) => [r.no, r.tanggal, r.keterangan, r.kategori, r.jenis, r.jumlahFmt]),
      styles: { fontSize: 8, cellPadding: 3 },
      headStyles: { fillColor: [37, 99, 235], textColor: 255, fontStyle: "bold" },
      alternateRowStyles: { fillColor: [248, 250, 252] },
      columnStyles: {
        0: { halign: "center", cellWidth: 10 },
        4: { halign: "center" },
        5: { halign: "right" },
      },
    });

    // Ringkasan
    const finalY = (doc as any).lastAutoTable.finalY + 8;
    autoTable(doc, {
      startY: finalY,
      head: [["Ringkasan", "Jumlah"]],
      body: [
        ["Total Pemasukan", formatCurrency(totalPemasukan)],
        ["Total Pengeluaran", formatCurrency(totalPengeluaran)],
        ["Saldo Akhir", formatCurrency(saldo)],
      ],
      styles: { fontSize: 9 },
      headStyles: { fillColor: [71, 85, 105], textColor: 255, fontStyle: "bold" },
      columnStyles: { 1: { halign: "right", fontStyle: "bold" } },
      tableWidth: 100,
      margin: { left: doc.internal.pageSize.width - 110 },
    });

    doc.save(`Laporan_Keuangan_${Date.now()}.pdf`);
    toast.success("Export PDF berhasil!");
    setOpen(false);
  };

  return (
    <div className="relative">
      <button
        onClick={() => setOpen((v) => !v)}
        className="inline-flex items-center gap-2 px-4 py-2.5 border border-slate-200 bg-white hover:bg-slate-50 text-slate-700 text-sm font-bold rounded-xl shadow-sm transition-colors"
      >
        <Download className="w-4 h-4" />
        Export
        <ChevronDown className={`w-3.5 h-3.5 transition-transform ${open ? "rotate-180" : ""}`} />
      </button>

      {open && (
        <>
          <div className="fixed inset-0 z-10" onClick={() => setOpen(false)} />
          <div className="absolute right-0 top-full mt-2 w-44 bg-white border border-slate-200 rounded-xl shadow-lg z-20 overflow-hidden">
            <button
              onClick={exportExcel}
              className="w-full flex items-center gap-3 px-4 py-3 text-sm font-semibold text-slate-700 hover:bg-slate-50 transition-colors"
            >
              <FileSpreadsheet className="w-4 h-4 text-emerald-600" />
              Export Excel
            </button>
            <button
              onClick={exportPDF}
              className="w-full flex items-center gap-3 px-4 py-3 text-sm font-semibold text-slate-700 hover:bg-slate-50 transition-colors border-t border-slate-100"
            >
              <FileText className="w-4 h-4 text-red-500" />
              Export PDF
            </button>
          </div>
        </>
      )}
    </div>
  );
}

