"use client";

import { useState, useEffect, useRef } from "react";
import { Bell, X, CheckCheck, Info, AlertTriangle, CheckCircle2, XCircle } from "lucide-react";
import { formatRelativeTime } from "@/lib/utils";

interface Notif {
  id: string;
  title: string;
  message: string;
  type: string;
  isRead: boolean;
  createdAt: string;
}

const typeIcon: Record<string, React.ReactNode> = {
  info: <Info className="w-4 h-4 text-blue-500" />,
  warning: <AlertTriangle className="w-4 h-4 text-amber-500" />,
  success: <CheckCircle2 className="w-4 h-4 text-green-500" />,
  error: <XCircle className="w-4 h-4 text-red-500" />,
};

const typeBg: Record<string, string> = {
  info: "bg-blue-50",
  warning: "bg-amber-50",
  success: "bg-green-50",
  error: "bg-red-50",
};

export default function NotificationBell() {
  const [open, setOpen] = useState(false);
  const [notifs, setNotifs] = useState<Notif[]>([]);
  const [unread, setUnread] = useState(0);
  const dropdownRef = useRef<HTMLDivElement>(null);

  const fetchNotifs = async () => {
    try {
      const res = await fetch("/api/notifikasi");
      if (!res.ok) return;
      const data = await res.json();
      setNotifs(data.notifs);
      setUnread(data.unreadCount);
    } catch {}
  };

  useEffect(() => {
    fetchNotifs();
    // Poll setiap 30 detik
    const interval = setInterval(fetchNotifs, 30000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const markAllRead = async () => {
    await fetch("/api/notifikasi", { method: "PATCH" });
    setNotifs((prev) => prev.map((n) => ({ ...n, isRead: true })));
    setUnread(0);
  };

  const markRead = async (id: string) => {
    await fetch(`/api/notifikasi/${id}`, { method: "PATCH" });
    setNotifs((prev) => prev.map((n) => (n.id === id ? { ...n, isRead: true } : n)));
    setUnread((prev) => Math.max(0, prev - 1));
  };

  const deleteNotif = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    await fetch(`/api/notifikasi/${id}`, { method: "DELETE" });
    const deleted = notifs.find((n) => n.id === id);
    setNotifs((prev) => prev.filter((n) => n.id !== id));
    if (deleted && !deleted.isRead) setUnread((prev) => Math.max(0, prev - 1));
  };

  return (
    <div className="relative" ref={dropdownRef}>
      <button
        onClick={() => {
          setOpen((v) => !v);
          if (!open && unread > 0) markAllRead();
        }}
        className="relative p-2 rounded-xl text-slate-500 hover:text-slate-800 hover:bg-slate-100 transition-colors"
        aria-label="Notifikasi"
      >
        <Bell className="w-5 h-5" />
        {unread > 0 && (
          <span className="absolute -top-0.5 -right-0.5 w-4 h-4 bg-red-500 text-white text-[9px] font-extrabold rounded-full flex items-center justify-center">
            {unread > 9 ? "9+" : unread}
          </span>
        )}
      </button>

      {open && (
        <div className="absolute right-0 top-full mt-2 w-80 bg-white border border-slate-200 rounded-2xl shadow-xl z-50 overflow-hidden">
          {/* Header */}
          <div className="px-4 py-3 border-b border-slate-100 flex items-center justify-between bg-slate-50">
            <div className="flex items-center gap-2">
              <Bell className="w-4 h-4 text-slate-600" />
              <span className="text-sm font-bold text-slate-800">Notifikasi</span>
              {unread > 0 && (
                <span className="px-1.5 py-0.5 bg-red-100 text-red-600 text-[10px] font-extrabold rounded-full">
                  {unread} baru
                </span>
              )}
            </div>
            {notifs.some((n) => !n.isRead) && (
              <button
                onClick={markAllRead}
                className="flex items-center gap-1 text-[11px] font-bold text-blue-600 hover:text-blue-700 transition-colors"
              >
                <CheckCheck className="w-3.5 h-3.5" />
                Tandai semua
              </button>
            )}
          </div>

          {/* List */}
          <div className="max-h-80 overflow-y-auto">
            {notifs.length === 0 ? (
              <div className="py-12 text-center">
                <Bell className="w-8 h-8 text-slate-200 mx-auto mb-2" />
                <p className="text-sm text-slate-400 font-medium">Tidak ada notifikasi</p>
              </div>
            ) : (
              notifs.map((n) => (
                <div
                  key={n.id}
                  onClick={() => !n.isRead && markRead(n.id)}
                  className={`flex items-start gap-3 px-4 py-3.5 border-b border-slate-50 last:border-0 cursor-pointer hover:bg-slate-50 transition-colors ${
                    !n.isRead ? "bg-blue-50/40" : ""
                  }`}
                >
                  <div className={`w-8 h-8 rounded-xl flex items-center justify-center shrink-0 ${typeBg[n.type] || typeBg.info}`}>
                    {typeIcon[n.type] || typeIcon.info}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className={`text-sm leading-snug ${!n.isRead ? "font-bold text-slate-900" : "font-semibold text-slate-700"}`}>
                      {n.title}
                    </p>
                    <p className="text-[11px] text-slate-500 mt-0.5 line-clamp-2">{n.message}</p>
                    <p className="text-[10px] text-slate-400 mt-1 font-medium">
                      {formatRelativeTime(n.createdAt)}
                    </p>
                  </div>
                  <div className="flex flex-col items-end gap-1 shrink-0">
                    {!n.isRead && (
                      <div className="w-2 h-2 bg-blue-500 rounded-full" />
                    )}
                    <button
                      onClick={(e) => deleteNotif(n.id, e)}
                      className="p-1 text-slate-300 hover:text-red-400 rounded transition-colors"
                    >
                      <X className="w-3 h-3" />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useRef } from "react";
import { ImageIcon, Upload, X, Loader2 } from "lucide-react";
import { supabaseAdmin } from "@/lib/supabase";
import { toast } from "sonner";

interface ThumbnailUploadProps {
  name?: string;
  defaultUrl?: string | null;
  bucket?: string;
  folder?: string;
  label?: string;
}

export default function ThumbnailUpload({
  name = "thumbnail",
  defaultUrl,
  bucket = "galeri",
  folder = "thumbnails",
  label = "Thumbnail",
}: ThumbnailUploadProps) {
  const [preview, setPreview] = useState<string | null>(defaultUrl || null);
  const [uploading, setUploading] = useState(false);
  const [uploadedUrl, setUploadedUrl] = useState<string>(defaultUrl || "");
  const inputRef = useRef<HTMLInputElement>(null);

  const handleFile = async (file: File) => {
    if (!file.type.startsWith("image/")) {
      toast.error("File harus berupa gambar (JPG, PNG, WebP)");
      return;
    }
    if (file.size > 5 * 1024 * 1024) {
      toast.error("Ukuran file maksimal 5MB");
      return;
    }

    setUploading(true);
    try {
      const ext = file.name.split(".").pop();
      const path = `${folder}/${Date.now()}.${ext}`;

      const { error } = await supabaseAdmin.storage
        .from(bucket)
        .upload(path, file, { upsert: true });

      if (error) throw error;

      const { data } = supabaseAdmin.storage.from(bucket).getPublicUrl(path);
      setUploadedUrl(data.publicUrl);
      setPreview(data.publicUrl);
      toast.success("Thumbnail berhasil diupload");
    } catch (err: any) {
      toast.error("Gagal upload: " + (err.message || "Coba lagi"));
    } finally {
      setUploading(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    const file = e.dataTransfer.files[0];
    if (file) handleFile(file);
  };

  const handleRemove = () => {
    setPreview(null);
    setUploadedUrl("");
    if (inputRef.current) inputRef.current.value = "";
  };

  return (
    <div className="space-y-2">
      <label className="text-sm font-bold text-slate-700">{label}</label>

      {/* Hidden input yang menyimpan URL untuk dikirim ke server action */}
      <input type="hidden" name={name} value={uploadedUrl} />

      {preview ? (
        <div className="relative w-full aspect-video rounded-xl overflow-hidden border border-slate-200 bg-slate-50 group">
          <img
            src={preview}
            alt="Thumbnail preview"
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-3">
            <button
              type="button"
              onClick={() => inputRef.current?.click()}
              disabled={uploading}
              className="flex items-center gap-1.5 px-3 py-2 bg-white text-slate-800 text-xs font-bold rounded-lg hover:bg-slate-100 transition-colors"
            >
              <Upload className="w-3.5 h-3.5" />
              Ganti
            </button>
            <button
              type="button"
              onClick={handleRemove}
              className="flex items-center gap-1.5 px-3 py-2 bg-red-500 text-white text-xs font-bold rounded-lg hover:bg-red-600 transition-colors"
            >
              <X className="w-3.5 h-3.5" />
              Hapus
            </button>
          </div>
          {uploading && (
            <div className="absolute inset-0 bg-white/70 flex items-center justify-center">
              <Loader2 className="w-6 h-6 animate-spin text-blue-500" />
            </div>
          )}
        </div>
      ) : (
        <div
          onDrop={handleDrop}
          onDragOver={(e) => e.preventDefault()}
          onClick={() => !uploading && inputRef.current?.click()}
          className="w-full aspect-video rounded-xl border-2 border-dashed border-slate-200 bg-slate-50 hover:border-blue-400 hover:bg-blue-50/30 transition-all cursor-pointer flex flex-col items-center justify-center gap-3 group"
        >
          {uploading ? (
            <>
              <Loader2 className="w-8 h-8 animate-spin text-blue-500" />
              <p className="text-sm font-medium text-slate-500">Mengupload...</p>
            </>
          ) : (
            <>
              <div className="w-12 h-12 bg-slate-100 group-hover:bg-blue-100 rounded-xl flex items-center justify-center transition-colors">
                <ImageIcon className="w-6 h-6 text-slate-400 group-hover:text-blue-500 transition-colors" />
              </div>
              <div className="text-center">
                <p className="text-sm font-bold text-slate-600 group-hover:text-blue-600 transition-colors">
                  Klik atau drag & drop gambar
                </p>
                <p className="text-xs text-slate-400 mt-1">JPG, PNG, WebP · Maks 5MB</p>
              </div>
            </>
          )}
        </div>
      )}

      <input
        ref={inputRef}
        type="file"
        accept="image/*"
        className="hidden"
        onChange={(e) => {
          const file = e.target.files?.[0];
          if (file) handleFile(file);
        }}
      />
    </div>
  );
}

"use client";

import { useState } from "react";
import { UserPlus, UserMinus, Loader2 } from "lucide-react";
import { toast } from "sonner";
import { useRouter } from "next/navigation";

interface Props {
  kegiatanId: string;
  terdaftar: boolean;
}

export default function DaftarKegiatanButton({ kegiatanId, terdaftar }: Props) {
  const [loading, setLoading] = useState(false);
  const router = useRouter();

  const handleClick = async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/kegiatan/daftar", {
        method: terdaftar ? "DELETE" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ kegiatanId }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Terjadi kesalahan");
      toast.success(terdaftar ? "Pendaftaran dibatalkan" : "Berhasil mendaftar kegiatan!");
      router.refresh();
    } catch (err: any) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  if (terdaftar) {
    return (
      <button
        onClick={handleClick}
        disabled={loading}
        className="flex items-center gap-1 px-2.5 py-1.5 text-[11px] font-bold text-red-500 bg-red-50 hover:bg-red-100 rounded-lg transition-colors disabled:opacity-50"
      >
        {loading ? <Loader2 className="w-3 h-3 animate-spin" /> : <UserMinus className="w-3 h-3" />}
        Batalkan
      </button>
    );
  }

  return (
    <button
      onClick={handleClick}
      disabled={loading}
      className="flex items-center gap-1.5 px-3 py-2 text-[12px] font-bold text-white bg-blue-600 hover:bg-blue-700 rounded-xl transition-colors disabled:opacity-50 shadow-sm"
    >
      {loading ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <UserPlus className="w-3.5 h-3.5" />}
      Daftar
    </button>
  );
}

"use client";

import { useState, useRef } from "react";
import { Camera, Loader2, X, Check } from "lucide-react";
import { useRouter } from "next/navigation";

interface FotoUploadProps {
  currentFoto: string | null;
  avatarUrl: string;
  namaLengkap: string;
  anggotaId: string;
}

export default function FotoUpload({ currentFoto, avatarUrl, namaLengkap, anggotaId }: FotoUploadProps) {
  const [preview, setPreview] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);
  const [status, setStatus] = useState<"idle" | "success" | "error">("idle");
  const inputRef = useRef<HTMLInputElement>(null);
  const router = useRouter();

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 2 * 1024 * 1024) {
      setStatus("error");
      return;
    }
    const reader = new FileReader();
    reader.onload = () => setPreview(reader.result as string);
    reader.readAsDataURL(file);
  };

  const handleUpload = async () => {
    const file = inputRef.current?.files?.[0];
    if (!file) return;

    setUploading(true);
    setStatus("idle");

    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("anggotaId", anggotaId);

      const res = await fetch("/api/member/foto", {
        method: "POST",
        body: formData,
      });

      if (!res.ok) throw new Error("Upload gagal");

      setStatus("success");
      setPreview(null);
      router.refresh();
    } catch {
      setStatus("error");
    } finally {
      setUploading(false);
    }
  };

  const handleCancel = () => {
    setPreview(null);
    setStatus("idle");
    if (inputRef.current) inputRef.current.value = "";
  };

  const displayUrl = preview || avatarUrl;

  return (
    <div className="flex flex-col items-center gap-3">
      {/* Avatar */}
      <div className="relative group">
        <img
          src={displayUrl}
          alt={namaLengkap}
          className="w-24 h-24 rounded-2xl object-cover border-2 border-slate-200 shadow-sm"
        />
        {/* Camera overlay */}
        <button
          type="button"
          onClick={() => inputRef.current?.click()}
          className="absolute inset-0 rounded-2xl bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"
        >
          <Camera className="w-6 h-6 text-white" />
        </button>
      </div>

      {/* Hidden input */}
      <input
        ref={inputRef}
        type="file"
        accept="image/jpeg,image/png,image/webp"
        className="hidden"
        onChange={handleFileChange}
      />

      {/* Actions when preview selected */}
      {preview ? (
        <div className="flex gap-2">
          <button
            type="button"
            onClick={handleUpload}
            disabled={uploading}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-blue-600 text-white text-xs font-bold hover:bg-blue-700 transition-colors disabled:opacity-60"
          >
            {uploading ? <Loader2 className="w-3 h-3 animate-spin" /> : <Check className="w-3 h-3" />}
            {uploading ? "Mengupload..." : "Simpan Foto"}
          </button>
          <button
            type="button"
            onClick={handleCancel}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-slate-100 text-slate-600 text-xs font-bold hover:bg-slate-200 transition-colors"
          >
            <X className="w-3 h-3" />
            Batal
          </button>
        </div>
      ) : (
        <button
          type="button"
          onClick={() => inputRef.current?.click()}
          className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-slate-100 text-slate-600 text-xs font-semibold hover:bg-slate-200 transition-colors"
        >
          <Camera className="w-3 h-3" />
          Ganti Foto
        </button>
      )}

      {/* Status messages */}
      {status === "success" && (
        <p className="text-xs text-green-600 font-semibold flex items-center gap-1">
          <Check className="w-3 h-3" /> Foto berhasil diperbarui
        </p>
      )}
      {status === "error" && (
        <p className="text-xs text-red-500 font-semibold">
          Gagal upload. Maks 2MB (JPG/PNG/WebP)
        </p>
      )}

      <p className="text-[10px] text-slate-400">Maks 2MB · JPG, PNG, WebP</p>
    </div>
  );
}

"use client";

import { useState } from "react";
import { X, Download, Calendar, Image as ImageIcon, Video, ZoomIn } from "lucide-react";
import { format } from "date-fns";
import { id as localeId } from "date-fns/locale";
import { cn } from "@/lib/utils";

interface GaleriItem {
  id: string;
  judul: string;
  deskripsi: string | null;
  url: string;
  type: "FOTO" | "VIDEO";
  createdAt: Date;
  kegiatanNama: string;
  kegiatanId: string;
}

interface GaleriGridProps {
  items: GaleriItem[];
}

export default function GaleriGrid({ items }: GaleriGridProps) {
  const [selectedItem, setSelectedItem] = useState<GaleriItem | null>(null);
  const [viewType, setViewType] = useState<"all" | "foto" | "video">("all");

  const filteredItems = items.filter((item) => {
    if (viewType === "all") return true;
    return viewType === "foto" ? item.type === "FOTO" : item.type === "VIDEO";
  });

  const handleDownload = async (url: string, filename: string) => {
    try {
      const response = await fetch(url);
      const blob = await response.blob();
      const blobUrl = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = blobUrl;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      window.URL.revokeObjectURL(blobUrl);
    } catch (error) {
      console.error("Error downloading file:", error);
    }
  };

  return (
    <>
      {/* Filter Type */}
      <div className="flex gap-2 mb-6">
        <button
          onClick={() => setViewType("all")}
          className={cn(
            "px-4 py-2 rounded-lg text-sm font-semibold transition-all",
            viewType === "all"
              ? "bg-blue-600 text-white shadow-sm"
              : "bg-white text-slate-600 hover:bg-slate-50 border border-slate-200"
          )}
        >
          Semua ({items.length})
        </button>
        <button
          onClick={() => setViewType("foto")}
          className={cn(
            "px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2",
            viewType === "foto"
              ? "bg-blue-600 text-white shadow-sm"
              : "bg-white text-slate-600 hover:bg-slate-50 border border-slate-200"
          )}
        >
          <ImageIcon className="w-4 h-4" />
          Foto ({items.filter((i) => i.type === "FOTO").length})
        </button>
        <button
          onClick={() => setViewType("video")}
          className={cn(
            "px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2",
            viewType === "video"
              ? "bg-blue-600 text-white shadow-sm"
              : "bg-white text-slate-600 hover:bg-slate-50 border border-slate-200"
          )}
        >
          <Video className="w-4 h-4" />
          Video ({items.filter((i) => i.type === "VIDEO").length})
        </button>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {filteredItems.map((item) => (
          <div
            key={item.id}
            className="bg-white rounded-xl border border-slate-200 overflow-hidden hover:shadow-lg transition-all group cursor-pointer"
            onClick={() => setSelectedItem(item)}
          >
            {/* Thumbnail */}
            <div className="aspect-square bg-slate-100 relative overflow-hidden">
              {item.type === "FOTO" ? (
                <img
                  src={item.url}
                  alt={item.judul}
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                />
              ) : (
                <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-purple-500 to-purple-700">
                  <Video className="w-16 h-16 text-white/50" />
                </div>
              )}
              {/* Overlay */}
              <div className="absolute inset-0 bg-black/0 group-hover:bg-black/40 transition-all flex items-center justify-center">
                <ZoomIn className="w-8 h-8 text-white opacity-0 group-hover:opacity-100 transition-all" />
              </div>
              {/* Type Badge */}
              <div className="absolute top-2 right-2">
                <span
                  className={cn(
                    "px-2 py-1 rounded-md text-[10px] font-bold uppercase",
                    item.type === "FOTO"
                      ? "bg-blue-500 text-white"
                      : "bg-purple-500 text-white"
                  )}
                >
                  {item.type}
                </span>
              </div>
            </div>

            {/* Info */}
            <div className="p-3">
              <h3 className="font-bold text-sm text-slate-900 line-clamp-1 mb-1">
                {item.judul}
              </h3>
              <p className="text-xs text-slate-500 line-clamp-1 mb-2">
                {item.kegiatanNama}
              </p>
              <div className="flex items-center gap-1 text-[10px] text-slate-400">
                <Calendar className="w-3 h-3" />
                {format(new Date(item.createdAt), "d MMM yyyy", {
                  locale: localeId,
                })}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Lightbox Modal */}
      {selectedItem && (
        <div
          className="fixed inset-0 bg-black/90 z-50 flex items-center justify-center p-4"
          onClick={() => setSelectedItem(null)}
        >
          <div
            className="relative max-w-6xl w-full"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Close Button */}
            <button
              onClick={() => setSelectedItem(null)}
              className="absolute -top-12 right-0 p-2 rounded-lg bg-white/10 hover:bg-white/20 text-white transition-all"
            >
              <X className="w-6 h-6" />
            </button>

            {/* Content */}
            <div className="bg-white rounded-2xl overflow-hidden">
              {/* Media */}
              <div className="bg-slate-900 flex items-center justify-center max-h-[70vh]">
                {selectedItem.type === "FOTO" ? (
                  <img
                    src={selectedItem.url}
                    alt={selectedItem.judul}
                    className="max-w-full max-h-[70vh] object-contain"
                  />
                ) : (
                  <video
                    src={selectedItem.url}
                    controls
                    className="max-w-full max-h-[70vh]"
                  >
                    Browser Anda tidak mendukung video.
                  </video>
                )}
              </div>

              {/* Info */}
              <div className="p-6">
                <div className="flex items-start justify-between gap-4 mb-4">
                  <div className="flex-1">
                    <h2 className="text-xl font-bold text-slate-900 mb-2">
                      {selectedItem.judul}
                    </h2>
                    <p className="text-sm text-slate-600 mb-3">
                      {selectedItem.kegiatanNama}
                    </p>
                    {selectedItem.deskripsi && (
                      <p className="text-sm text-slate-600">
                        {selectedItem.deskripsi}
                      </p>
                    )}
                  </div>
                  <button
                    onClick={() =>
                      handleDownload(
                        selectedItem.url,
                        `${selectedItem.judul}.${selectedItem.type === "FOTO" ? "jpg" : "mp4"}`
                      )
                    }
                    className="flex items-center gap-2 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700 transition-all text-sm font-semibold shrink-0"
                  >
                    <Download className="w-4 h-4" />
                    Download
                  </button>
                </div>

                <div className="flex items-center gap-4 text-sm text-slate-500">
                  <div className="flex items-center gap-2">
                    <Calendar className="w-4 h-4" />
                    {format(new Date(selectedItem.createdAt), "d MMMM yyyy", {
                      locale: localeId,
                    })}
                  </div>
                  <div className="flex items-center gap-2">
                    {selectedItem.type === "FOTO" ? (
                      <ImageIcon className="w-4 h-4" />
                    ) : (
                      <Video className="w-4 h-4" />
                    )}
                    {selectedItem.type}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

"use client";

import { useState } from "react";
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameMonth, isSameDay, isToday, addMonths, subMonths } from "date-fns";
import { id as localeId } from "date-fns/locale";
import { ChevronLeft, ChevronRight, MapPin, Clock, CheckCircle } from "lucide-react";
import { cn } from "@/lib/utils";

interface Event {
  id: string;
  title: string;
  start: Date;
  end: Date;
  location?: string | null;
  description?: string | null;
  status: string;
  isRegistered: boolean;
}

interface KalenderKegiatanProps {
  events: Event[];
}

export default function KalenderKegiatan({ events }: KalenderKegiatanProps) {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);

  const monthStart = startOfMonth(currentMonth);
  const monthEnd = endOfMonth(currentMonth);
  const daysInMonth = eachDayOfInterval({ start: monthStart, end: monthEnd });

  // Get events for selected date
  const selectedEvents = selectedDate
    ? events.filter((e) => isSameDay(new Date(e.start), selectedDate))
    : [];

  // Get events for a specific day
  const getEventsForDay = (day: Date) => {
    return events.filter((e) => isSameDay(new Date(e.start), day));
  };

  const prevMonth = () => setCurrentMonth(subMonths(currentMonth, 1));
  const nextMonth = () => setCurrentMonth(addMonths(currentMonth, 1));

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      {/* Calendar */}
      <div className="lg:col-span-2 bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-bold text-slate-900">
            {format(currentMonth, "MMMM yyyy", { locale: localeId })}
          </h2>
          <div className="flex gap-2">
            <button
              onClick={prevMonth}
              className="p-2 rounded-lg hover:bg-slate-100 transition-colors"
            >
              <ChevronLeft className="w-5 h-5 text-slate-600" />
            </button>
            <button
              onClick={nextMonth}
              className="p-2 rounded-lg hover:bg-slate-100 transition-colors"
            >
              <ChevronRight className="w-5 h-5 text-slate-600" />
            </button>
          </div>
        </div>

        {/* Days of Week */}
        <div className="grid grid-cols-7 gap-2 mb-2">
          {["Min", "Sen", "Sel", "Rab", "Kam", "Jum", "Sab"].map((day) => (
            <div
              key={day}
              className="text-center text-xs font-bold text-slate-500 py-2"
            >
              {day}
            </div>
          ))}
        </div>

        {/* Calendar Grid */}
        <div className="grid grid-cols-7 gap-2">
          {daysInMonth.map((day) => {
            const dayEvents = getEventsForDay(day);
            const hasEvents = dayEvents.length > 0;
            const isSelected = selectedDate && isSameDay(day, selectedDate);
            const isTodayDate = isToday(day);

            return (
              <button
                key={day.toString()}
                onClick={() => setSelectedDate(day)}
                className={cn(
                  "aspect-square p-2 rounded-lg text-sm font-semibold transition-all relative",
                  isTodayDate && "ring-2 ring-blue-500",
                  isSelected && "bg-blue-600 text-white",
                  !isSelected && isTodayDate && "bg-blue-50 text-blue-600",
                  !isSelected && !isTodayDate && hasEvents && "bg-green-50 text-green-700 hover:bg-green-100",
                  !isSelected && !isTodayDate && !hasEvents && "text-slate-600 hover:bg-slate-50"
                )}
              >
                {format(day, "d")}
                {hasEvents && !isSelected && (
                  <div className="absolute bottom-1 left-1/2 -translate-x-1/2 flex gap-0.5">
                    {dayEvents.slice(0, 3).map((_, i) => (
                      <div
                        key={i}
                        className="w-1 h-1 rounded-full bg-green-500"
                      />
                    ))}
                  </div>
                )}
              </button>
            );
          })}
        </div>

        {/* Legend */}
        <div className="flex items-center gap-4 mt-6 pt-6 border-t border-slate-100">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-blue-500" />
            <span className="text-xs text-slate-600">Hari Ini</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-green-500" />
            <span className="text-xs text-slate-600">Ada Kegiatan</span>
          </div>
        </div>
      </div>

      {/* Event List */}
      <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
        <h3 className="text-sm font-bold text-slate-900 mb-4">
          {selectedDate
            ? `Kegiatan ${format(selectedDate, "d MMMM yyyy", { locale: localeId })}`
            : "Pilih Tanggal"}
        </h3>

        {selectedDate ? (
          selectedEvents.length > 0 ? (
            <div className="space-y-3">
              {selectedEvents.map((event) => (
                <div
                  key={event.id}
                  className="p-4 rounded-xl border border-slate-100 bg-slate-50 hover:bg-blue-50 hover:border-blue-200 transition-all"
                >
                  <div className="flex items-start justify-between gap-2 mb-2">
                    <h4 className="font-bold text-sm text-slate-900">
                      {event.title}
                    </h4>
                    {event.isRegistered && (
                      <CheckCircle className="w-4 h-4 text-green-500 shrink-0" />
                    )}
                  </div>

                  {event.location && (
                    <div className="flex items-center gap-2 text-xs text-slate-600 mb-1">
                      <MapPin className="w-3 h-3" />
                      {event.location}
                    </div>
                  )}

                  <div className="flex items-center gap-2 text-xs text-slate-600">
                    <Clock className="w-3 h-3" />
                    {format(new Date(event.start), "HH:mm", { locale: localeId })}
                  </div>

                  {event.description && (
                    <p className="text-xs text-slate-500 mt-2 line-clamp-2">
                      {event.description}
                    </p>
                  )}

                  <button
                    className={cn(
                      "w-full mt-3 px-3 py-2 rounded-lg text-xs font-semibold transition-all",
                      event.isRegistered
                        ? "bg-green-100 text-green-700 cursor-default"
                        : "bg-blue-600 text-white hover:bg-blue-700"
                    )}
                    disabled={event.isRegistered}
                  >
                    {event.isRegistered ? "Sudah Terdaftar" : "Daftar Kegiatan"}
                  </button>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-8">
              <p className="text-sm text-slate-500">
                Tidak ada kegiatan pada tanggal ini
              </p>
            </div>
          )
        ) : (
          <div className="text-center py-8">
            <p className="text-sm text-slate-500">
              Klik tanggal di kalender untuk melihat kegiatan
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

