"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import {
  Menu,
  X,
  Lock,
  Home,
  Info,
  Calendar,
  Newspaper,
  FileText,
  Image as ImageIcon,
  ChevronRight,
  ClipboardList,
} from "lucide-react";

const navLinks = [
  { label: "Beranda", href: "/", icon: Home },
  { label: "Tentang", href: "/tentang", icon: Info },
  { label: "Kegiatan", href: "/kegiatan", icon: Calendar },
  { label: "Berita", href: "/berita", icon: Newspaper },
  { label: "Artikel", href: "/artikel", icon: FileText },
  { label: "Galeri", href: "/galeri", icon: ImageIcon },
  { label: "Kuisioner", href: "/sus", icon: ClipboardList },
];

export default function Navbar({ session }: { session: any }) {
  const [mobileOpen, setMobileOpen] = useState(false);
  const pathname = usePathname();

  // Close mobile menu on route change
  useEffect(() => {
    setMobileOpen(false);
  }, [pathname]);

  const isActive = (href: string) => {
    if (href === "/") return pathname === "/";
    return pathname.startsWith(href);
  };

  return (
    <header className="fixed top-0 left-0 right-0 z-50 bg-white border-b border-gray-100 shadow-sm">
      <nav className="w-full max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-[72px]">

          {/* Logo Area */}
          <Link href="/" className="flex items-center gap-3">
            <img 
              src="/logo.png" 
              alt="Logo" 
              className="w-10 h-10 object-contain rounded-full border border-gray-100"
              onError={(e) => {
                // Fallback to a styled div if logo.png doesn't exist
                e.currentTarget.style.display = 'none';
                if (e.currentTarget.nextElementSibling) {
                  (e.currentTarget.nextElementSibling as HTMLElement).style.display = 'flex';
                }
              }}
            />
            {/* Fallback Icon */}
            <div className="hidden w-10 h-10 bg-blue-50 text-blue-600 rounded-full items-center justify-center border border-blue-100">
              <span className="font-bold">KT</span>
            </div>

            <div className="flex flex-col">
              <span className="text-[16px] font-extrabold text-slate-900 leading-tight">
                Karang Taruna
              </span>
              <span className="text-[11px] font-bold text-blue-500 leading-tight">
                Generasi Emas
              </span>
            </div>
            <div className="ml-2 hidden sm:flex items-center gap-1.5 px-2 py-0.5 bg-green-50 rounded-full border border-green-200">
              <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse" />
              <span className="text-[10px] font-bold text-green-600">Online</span>
            </div>
          </Link>

          {/* Desktop Nav Links */}
          <div className="hidden lg:flex items-center gap-1">
            {navLinks.map((link: any) => {
              const active = isActive(link.href);
              const Icon = link.icon;
              return (
                <Link
                  key={link.href}
                  href={link.href}
                  className={`flex items-center gap-1.5 px-3 py-2 rounded-md text-[13px] font-bold transition-all ${
                    active
                      ? "bg-slate-100 text-slate-900"
                      : "text-slate-500 hover:text-slate-900 hover:bg-slate-50"
                  }`}
                >
                  <Icon className={`w-4 h-4 ${active ? "text-slate-700" : "text-slate-400"}`} />
                  {link.label}
                </Link>
              );
            })}
          </div>

          {/* Right: Login Button or Dashboard Button */}
          <div className="hidden lg:flex items-center">
            {session ? (
              <Link
                href={(session.user as any)?.role === "ADMIN" || (session.user as any)?.role === "SUPER_ADMIN" ? "/dashboard" : "/member/dashboard"}
                className="flex items-center gap-2 px-5 py-2.5 text-[13px] font-bold text-white bg-green-600 hover:bg-green-700 rounded-lg transition-colors shadow-sm shadow-green-500/20"
              >
                <Home className="w-4 h-4" />
                {(session.user as any)?.role === "ADMIN" || (session.user as any)?.role === "SUPER_ADMIN" ? "Dashboard Admin" : "Dashboard Anggota"}
              </Link>
            ) : (
              <Link
                href="/anggota/login"
                className="flex items-center gap-2 px-5 py-2.5 text-[13px] font-bold text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors shadow-sm shadow-blue-500/20"
              >
                <Lock className="w-4 h-4" />
                Login Anggota
              </Link>
            )}
          </div>

          {/* Mobile Hamburger */}
          <button
            onClick={() => setMobileOpen((v) => !v)}
            className="lg:hidden p-2 rounded-lg hover:bg-slate-100 text-slate-600 transition-colors"
            aria-label="Toggle menu"
          >
            {mobileOpen ? (
              <X className="w-6 h-6" />
            ) : (
              <Menu className="w-6 h-6" />
            )}
          </button>
        </div>

        {/* Mobile Menu */}
        <AnimatePresence>
          {mobileOpen && (
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: "auto", opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              transition={{ duration: 0.2, ease: "easeInOut" }}
              className="lg:hidden border-t border-gray-100 bg-white"
            >
              <div className="px-2 py-4 flex flex-col gap-1">
                {navLinks.map((link: any, i: number) => {
                  const active = isActive(link.href);
                  const Icon = link.icon;
                  return (
                    <motion.div
                      key={link.href}
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: i * 0.03 }}
                    >
                      <Link
                        href={link.href}
                        className={`flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all ${
                          active
                            ? "bg-slate-100 text-slate-900"
                            : "text-slate-600 hover:bg-slate-50"
                        }`}
                      >
                        <Icon className={`w-5 h-5 ${active ? "text-slate-700" : "text-slate-400"}`} />
                        {link.label}
                        {active && <ChevronRight className="w-4 h-4 text-slate-400 ml-auto" />}
                      </Link>
                    </motion.div>
                  );
                })}

                <motion.div
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: navLinks.length * 0.03 + 0.1 }}
                  className="mt-2 pt-4 border-t border-gray-100 px-2"
                >
                  {session ? (
                    <Link
                      href={(session.user as any)?.role === "ADMIN" || (session.user as any)?.role === "SUPER_ADMIN" ? "/dashboard" : "/member/dashboard"}
                      className="flex items-center justify-center gap-2 w-full px-5 py-3.5 rounded-xl text-sm font-bold text-white bg-green-600 hover:bg-green-700 shadow-sm transition-colors"
                    >
                      <Home className="w-5 h-5" />
                      {(session.user as any)?.role === "ADMIN" || (session.user as any)?.role === "SUPER_ADMIN" ? "Dashboard Admin" : "Dashboard Anggota"}
                    </Link>
                  ) : (
                    <Link
                      href="/anggota/login"
                      className="flex items-center justify-center gap-2 w-full px-5 py-3.5 rounded-xl text-sm font-bold text-white bg-blue-600 hover:bg-blue-700 shadow-sm transition-colors"
                    >
                      <Lock className="w-5 h-5" />
                      Login Anggota
                    </Link>
                  )}
                </motion.div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </nav>
    </header>
  );
}

import Link from "next/link";
import {
  ShoppingBag,
  GraduationCap,
  Heart,
  Trophy,
  Leaf,
  HandHeart,
  ArrowRight,
} from "lucide-react";

import { prisma } from "@/lib/prisma";
import * as LucideIcons from "lucide-react";

export default async function ProgramSection() {
  const programs = await prisma.program.findMany({
    where: { status: true },
    orderBy: { urutan: "asc" },
  });

  // Helper function to dynamically render Lucide icons
  const getIcon = (iconName: string | null) => {
    if (!iconName) return LucideIcons.ShoppingBag;
    return (LucideIcons as any)[iconName] || LucideIcons.ShoppingBag;
  };
  return (
    <section className="py-20 md:py-28 bg-[#f4f9ff]">
      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-14">
          <span className="inline-flex items-center gap-1.5 px-3 py-1 bg-blue-100 rounded-full text-[11px] font-extrabold text-blue-600 uppercase tracking-wide mb-4">
            Program Kami
          </span>
          <h2 className="text-3xl md:text-[40px] font-extrabold text-slate-900 mb-4 leading-tight">
            Program{" "}
            <span className="text-blue-500">Unggulan Kami</span>
          </h2>
          <p className="text-slate-600 max-w-2xl mx-auto text-[15px] md:text-[16px]">
            Enam bidang program strategis yang kami kembangkan untuk memaksimalkan
            potensi pemuda dan memberikan dampak positif bagi masyarakat.
          </p>
        </div>

        {/* Program Cards Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {programs.length === 0 ? (
            <p className="text-slate-500 col-span-full text-center">Belum ada program unggulan.</p>
          ) : (
            programs.map((program: any) => {
              const Icon = getIcon(program.icon);
              return (
                <div
                  key={program.id}
                  className={`group bg-white border border-slate-100 rounded-2xl p-6 transition-all duration-300 hover:-translate-y-1 shadow-sm hover:shadow-md flex flex-col`}
                >
                  {/* Icon */}
                  <div
                    className={`w-12 h-12 rounded-xl bg-blue-50 flex items-center justify-center mb-5 group-hover:scale-110 transition-transform duration-300`}
                  >
                    <Icon className={`w-6 h-6 text-blue-500`} />
                  </div>

                  <h3 className="text-[17px] font-bold text-slate-900 mb-2">
                    {program.nama}
                  </h3>
                  <p className="text-[13px] text-slate-600 leading-relaxed mb-6 flex-1">
                    {program.deskripsi}
                  </p>

                  <Link
                    href={`/program`}
                    className={`inline-flex items-center gap-1.5 text-[13px] font-bold text-blue-600 hover:gap-2.5 transition-all mt-auto`}
                  >
                    Selengkapnya
                    <ArrowRight className="w-4 h-4" />
                  </Link>
                </div>
              );
            })
          )}
        </div>

        {/* View all CTA */}
        <div className="text-center mt-12">
          <Link
            href="/program"
            className="inline-flex items-center gap-2 px-8 py-3.5 border-2 border-blue-500 text-blue-500 font-bold rounded-xl hover:bg-blue-50 transition-colors shadow-sm"
          >
            Lihat Semua Program
            <ArrowRight className="w-4 h-4" />
          </Link>
        </div>
      </div>
    </section>
  );
}

"use client";

import * as React from "react";
import {
  useReactTable,
  getCoreRowModel,
  getSortedRowModel,
  flexRender,
  type ColumnDef,
  type SortingState,
} from "@tanstack/react-table";
import {
  ChevronUp,
  ChevronDown,
  ChevronsUpDown,
  ChevronLeft,
  ChevronRight,
  ChevronsLeft,
  ChevronsRight,
  Search,
  FileSpreadsheet,
  FileText,
  Inbox,
} from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { SkeletonTableRow } from "@/components/ui/skeleton";

// ─── Props ─────────────────────────────────────────────────────────────────

export interface DataTableProps<TData> {
  data: TData[];
  columns: ColumnDef<TData>[];
  isLoading?: boolean;
  searchPlaceholder?: string;
  onSearch?: (query: string) => void;
  searchValue?: string;
  totalItems?: number;
  page?: number;
  pageSize?: number;
  onPageChange?: (page: number) => void;
  onPageSizeChange?: (size: number) => void;
  onExportExcel?: () => void;
  onExportPDF?: () => void;
  filterSlot?: React.ReactNode;
  actionSlot?: React.ReactNode;
}

// ─── Debounce hook ─────────────────────────────────────────────────────────

function useDebounce<T>(value: T, delay = 300): T {
  const [debounced, setDebounced] = React.useState(value);
  React.useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);
  return debounced;
}

// ─── Component ─────────────────────────────────────────────────────────────

export function DataTable<TData>({
  data,
  columns,
  isLoading = false,
  searchPlaceholder = "Cari...",
  onSearch,
  searchValue: externalSearch,
  totalItems,
  page = 1,
  pageSize = 10,
  onPageChange,
  onPageSizeChange,
  onExportExcel,
  onExportPDF,
  filterSlot,
  actionSlot,
}: DataTableProps<TData>) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [localSearch, setLocalSearch] = React.useState(externalSearch ?? "");

  const debouncedSearch = useDebounce(localSearch, 300);

  // Propagate debounced search to parent
  React.useEffect(() => {
    onSearch?.(debouncedSearch);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [debouncedSearch]);

  // Keep in sync with external controlled value
  React.useEffect(() => {
    if (externalSearch !== undefined && externalSearch !== localSearch) {
      setLocalSearch(externalSearch);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [externalSearch]);

  const table = useReactTable({
    data,
    columns,
    state: { sorting },
    onSortingChange: setSorting,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    manualPagination: true,
    manualSorting: false,
  });

  const totalPages = totalItems !== undefined ? Math.ceil(totalItems / pageSize) : 1;
  const startItem = totalItems !== undefined && totalItems > 0 ? (page - 1) * pageSize + 1 : 0;
  const endItem = totalItems !== undefined ? Math.min(page * pageSize, totalItems) : data.length;

  // Page number buttons (max 5 around current)
  const pageNumbers = React.useMemo(() => {
    const delta = 2;
    const range: number[] = [];
    for (
      let i = Math.max(1, page - delta);
      i <= Math.min(totalPages, page + delta);
      i++
    ) {
      range.push(i);
    }
    return range;
  }, [page, totalPages]);

  const PAGE_SIZE_OPTIONS = ["10", "25", "50", "100"];

  return (
    <div className="space-y-4">
      {/* ── Toolbar ───────────────────────────────────────────── */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div className="flex items-center gap-2 flex-wrap flex-1">
          {onSearch !== undefined && (
            <div className="relative w-full sm:w-64">
              <Input
                placeholder={searchPlaceholder}
                value={localSearch}
                onChange={(e) => setLocalSearch(e.target.value)}
                leftIcon={<Search className="h-4 w-4" />}
                className="pr-3"
              />
            </div>
          )}
          {filterSlot}
        </div>

        <div className="flex items-center gap-2 shrink-0 flex-wrap">
          {onExportExcel && (
            <Button
              variant="outline"
              size="sm"
              onClick={onExportExcel}
              leftIcon={<FileSpreadsheet className="h-4 w-4 text-success" />}
            >
              Excel
            </Button>
          )}
          {onExportPDF && (
            <Button
              variant="outline"
              size="sm"
              onClick={onExportPDF}
              leftIcon={<FileText className="h-4 w-4 text-destructive" />}
            >
              PDF
            </Button>
          )}
          {actionSlot}
        </div>
      </div>

      {/* ── Table ─────────────────────────────────────────────── */}
      <div className="rounded-xl border border-border bg-card overflow-hidden card-shadow">
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              {table.getHeaderGroups().map((headerGroup) => (
                <tr
                  key={headerGroup.id}
                  className="border-b border-border bg-muted/50"
                >
                  {headerGroup.headers.map((header) => {
                    const canSort = header.column.getCanSort();
                    const sorted = header.column.getIsSorted();
                    return (
                      <th
                        key={header.id}
                        scope="col"
                        className={cn(
                          "px-4 py-3 text-left text-xs font-semibold text-muted-foreground uppercase tracking-wider whitespace-nowrap",
                          canSort && "cursor-pointer select-none hover:text-foreground transition-colors duration-150"
                        )}
                        onClick={canSort ? header.column.getToggleSortingHandler() : undefined}
                      >
                        <span className="inline-flex items-center gap-1">
                          {header.isPlaceholder
                            ? null
                            : flexRender(header.column.columnDef.header, header.getContext())}
                          {canSort && (
                            <span className="text-muted-foreground/50">
                              {sorted === "asc" ? (
                                <ChevronUp className="h-3 w-3 text-primary" />
                              ) : sorted === "desc" ? (
                                <ChevronDown className="h-3 w-3 text-primary" />
                              ) : (
                                <ChevronsUpDown className="h-3 w-3" />
                              )}
                            </span>
                          )}
                        </span>
                      </th>
                    );
                  })}
                </tr>
              ))}
            </thead>

            <tbody className="divide-y divide-border">
              {isLoading ? (
                <>
                  {Array.from({ length: 5 }).map((_, i) => (
                    <SkeletonTableRow
                      key={i}
                      columns={columns.length}
                    />
                  ))}
                </>
              ) : table.getRowModel().rows.length === 0 ? (
                <tr>
                  <td
                    colSpan={columns.length}
                    className="py-16 text-center"
                  >
                    <div className="flex flex-col items-center gap-3">
                      <div className="flex items-center justify-center w-12 h-12 rounded-xl bg-muted">
                        <Inbox className="h-6 w-6 text-muted-foreground/50" />
                      </div>
                      <div>
                        <p className="text-sm font-medium text-foreground">Tidak ada data</p>
                        <p className="text-xs text-muted-foreground mt-0.5">
                          {localSearch
                            ? `Tidak ada hasil untuk "${localSearch}"`
                            : "Belum ada data yang tersedia"}
                        </p>
                      </div>
                    </div>
                  </td>
                </tr>
              ) : (
                table.getRowModel().rows.map((row) => (
                  <tr
                    key={row.id}
                    className="hover:bg-muted/40 transition-colors duration-150"
                  >
                    {row.getVisibleCells().map((cell) => (
                      <td
                        key={cell.id}
                        className="px-4 py-3 text-sm text-foreground whitespace-nowrap"
                      >
                        {flexRender(cell.column.columnDef.cell, cell.getContext())}
                      </td>
                    ))}
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* ── Pagination ────────────────────────────────────────── */}
      {(onPageChange || onPageSizeChange) && (
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          {/* Info */}
          <p className="text-xs text-muted-foreground order-2 sm:order-1">
            {isLoading
              ? "Memuat data..."
              : totalItems !== undefined && totalItems > 0
              ? `Menampilkan ${startItem}–${endItem} dari ${totalItems.toLocaleString("id-ID")} data`
              : "Tidak ada data"}
          </p>

          <div className="flex items-center gap-3 order-1 sm:order-2 flex-wrap">
            {/* Page size */}
            {onPageSizeChange && (
              <div className="flex items-center gap-2">
                <span className="text-xs text-muted-foreground whitespace-nowrap">Baris:</span>
                <Select
                  value={String(pageSize)}
                  onValueChange={(v) => onPageSizeChange(Number(v))}
                >
                  <SelectTrigger className="h-8 w-16 text-xs">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {PAGE_SIZE_OPTIONS.map((s) => (
                      <SelectItem key={s} value={s}>
                        {s}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            )}

            {/* Page buttons */}
            {onPageChange && totalPages > 1 && (
              <div className="flex items-center gap-1">
                <Button
                  variant="outline"
                  size="icon-sm"
                  onClick={() => onPageChange(1)}
                  disabled={page <= 1 || isLoading}
                  aria-label="Halaman pertama"
                >
                  <ChevronsLeft className="h-3.5 w-3.5" />
                </Button>
                <Button
                  variant="outline"
                  size="icon-sm"
                  onClick={() => onPageChange(page - 1)}
                  disabled={page <= 1 || isLoading}
                  aria-label="Halaman sebelumnya"
                >
                  <ChevronLeft className="h-3.5 w-3.5" />
                </Button>

                {pageNumbers.map((p) => (
                  <Button
                    key={p}
                    variant={p === page ? "default" : "outline"}
                    size="icon-sm"
                    onClick={() => onPageChange(p)}
                    disabled={isLoading}
                    className={cn("text-xs", p === page && "pointer-events-none")}
                  >
                    {p}
                  </Button>
                ))}

                <Button
                  variant="outline"
                  size="icon-sm"
                  onClick={() => onPageChange(page + 1)}
                  disabled={page >= totalPages || isLoading}
                  aria-label="Halaman berikutnya"
                >
                  <ChevronRight className="h-3.5 w-3.5" />
                </Button>
                <Button
                  variant="outline"
                  size="icon-sm"
                  onClick={() => onPageChange(totalPages)}
                  disabled={page >= totalPages || isLoading}
                  aria-label="Halaman terakhir"
                >
                  <ChevronsRight className="h-3.5 w-3.5" />
                </Button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import * as React from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";

export interface FormModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  description?: string;
  children: React.ReactNode;
  footer?: React.ReactNode;
  maxWidth?: string;
  className?: string;
}

export function FormModal({
  isOpen,
  onClose,
  title,
  description,
  children,
  footer,
  maxWidth = "max-w-lg",
  className,
}: FormModalProps) {
  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open && onClose()}>
      <DialogContent
        className={cn(
          "flex flex-col max-h-[90vh] p-0 gap-0",
          maxWidth,
          className
        )}
      >
        {/* Header */}
        <DialogHeader className="px-6 pt-6 pb-4 border-b border-border shrink-0">
          <DialogTitle>{title}</DialogTitle>
          {description && (
            <DialogDescription>{description}</DialogDescription>
          )}
        </DialogHeader>

        {/* Scrollable body */}
        <ScrollArea className="flex-1 min-h-0">
          <div className="px-6 py-4">{children}</div>
        </ScrollArea>

        {/* Footer */}
        {footer && (
          <div className="px-6 pb-6 pt-4 border-t border-border shrink-0">
            <div className="flex items-center justify-end gap-3">{footer}</div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

"use client";

import * as React from "react";
import Link from "next/link";
import { type LucideIcon, TrendingUp, TrendingDown } from "lucide-react";
import { motion, useInView, useMotionValue, useTransform, animate } from "framer-motion";
import { cn } from "@/lib/utils";

export interface StatCardProps {
  title: string;
  value: number | string;
  icon: React.ReactNode;
  trend?: number;
  description?: string;
  iconBg?: string;
  href?: string;
  className?: string;
}

function AnimatedNumber({ value }: { value: number }) {
  const ref = React.useRef<HTMLSpanElement>(null);
  const motionValue = useMotionValue(0);
  const inView = useInView(ref, { once: true, margin: "-40px" });

  React.useEffect(() => {
    if (inView) {
      const controls = animate(motionValue, value, {
        duration: 1.2,
        ease: "easeOut",
      });
      return controls.stop;
    }
  }, [inView, value, motionValue]);

  React.useEffect(() => {
    const unsubscribe = motionValue.on("change", (latest) => {
      if (ref.current) {
        ref.current.textContent = Math.round(latest).toLocaleString("id-ID");
      }
    });
    return unsubscribe;
  }, [motionValue]);

  return <span ref={ref}>0</span>;
}

export function StatCard({
  title,
  value,
  icon,
  trend,
  description,
  iconBg = "bg-primary/10",
  href,
  className,
}: StatCardProps) {
  const isNumeric = typeof value === "number";
  const isPositiveTrend = trend !== undefined && trend > 0;
  const isNegativeTrend = trend !== undefined && trend < 0;

  const cardContent = (
    <div
      className={cn(
        "bg-card rounded-xl border border-border card-shadow-md p-6 transition-all duration-200",
        href && "hover:card-shadow-lg hover:-translate-y-0.5 cursor-pointer",
        className
      )}
    >
      <div className="flex items-start justify-between mb-4">
        <div className="space-y-1 min-w-0 flex-1">
          <p className="text-sm text-muted-foreground font-medium truncate">{title}</p>
          <p className="text-2xl font-bold text-foreground leading-tight">
            {isNumeric ? (
              <AnimatedNumber value={value as number} />
            ) : (
              value
            )}
          </p>
        </div>

        <div
          className={cn(
            "flex-shrink-0 flex items-center justify-center h-12 w-12 rounded-xl",
            iconBg
          )}
        >
          {icon}
        </div>
      </div>

      {/* Trend + description */}
      <div className="flex items-center gap-2 flex-wrap">
        {trend !== undefined && (
          <span
            className={cn(
              "inline-flex items-center gap-0.5 text-xs font-semibold rounded-full px-2 py-0.5",
              isPositiveTrend && "text-success bg-success/10",
              isNegativeTrend && "text-destructive bg-destructive/10",
              trend === 0 && "text-muted-foreground bg-muted"
            )}
          >
            {isPositiveTrend ? (
              <TrendingUp className="h-3 w-3" />
            ) : isNegativeTrend ? (
              <TrendingDown className="h-3 w-3" />
            ) : null}
            {trend > 0 ? "+" : ""}
            {trend}%
          </span>
        )}
        {description && (
          <span className="text-xs text-muted-foreground">{description}</span>
        )}
      </div>
    </div>
  );

  if (href) {
    return (
      <Link href={href} className="block">
        {cardContent}
      </Link>
    );
  }

  return cardContent;
}

